<template>
  <div class="account-list">
    <div class="page-container">
      <!-- 左侧平台列表 -->
      <div class="left-sidebar">
        <div class="sidebar-header">
          <h3 class="sidebar-title">授权平台</h3>
        </div>
        <div class="platform-list">
          <div 
            v-for="platform in platforms" 
            :key="platform.platform_type"
            :class="['platform-item', { 'platform-item-active': selectedPlatform === platform.platform_type }]"
            @click="filterByPlatform(platform.platform_type)">
            <div class="platform-item-inner">
              <div class="platform-item-icon">
                <el-avatar :size="32" :src="platform.avatar"></el-avatar>
              </div>
              <div class="platform-item-info">
                <span class="platform-item-name">{{ platform.name }}</span>
                <span class="platform-item-count">{{ platform.count }}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 右侧内容区域 -->
      <div class="right-content">
        <!-- 顶部搜索和操作区域 -->
        <div class="top-bar">
          <div class="search-container">
            <el-input
              v-model="searchForm.name"
              placeholder="请输入昵称"
              prefix-icon="el-icon-search"
              class="search-input"
            />
            <el-select v-model="searchForm.status" placeholder="授权状态" class="status-select" @change="handleSearch" clearable @clear="handleSearch">
              <el-option label="全部" value=""></el-option>
              <el-option label="已授权" value="true"></el-option>
              <el-option label="授权过期" value="false"></el-option>
            </el-select>
          </div>
          <div class="action-buttons">
            <!-- <el-button type="primary" class="action-button">
              一键检测授权
            </el-button> -->
            <el-button type="primary" class="action-button" @click="refreshAccounts">
              <i class="el-icon-refresh"></i>
              刷新列表
            </el-button>
            <el-button type="success" class="action-button" @click="openAddAccountDialog">
              + 新增授权
            </el-button>
            <el-button v-if="sendArticleStatus" type="warning" class="action-button" @click="openPushDrawer">
              发布
            </el-button>
          </div>
        </div>

        <!-- 账号列表 -->
        <div class="account-table-container" v-if="!src_url">
          <el-table
            :data="filteredAccountList"
            v-loading="loading"
            style="width: 100%"
            class="account-table"
            ref="multipleTable"
            >
            <el-table-column label="头像" min-width="80" align="center">
              <template slot-scope="scope">
                <el-avatar :size="32" :src="scope.row.avatar" class="nickname-avatar"></el-avatar>
              </template>
            </el-table-column>
            <el-table-column prop="name" label="昵称" min-width="120" align="center">
              <template slot-scope="scope">
                <span class="nickname-text">{{ scope.row.name }}</span>
              </template>
            </el-table-column>
            <el-table-column label="平台" min-width="120" align="center">
              <template slot-scope="scope">
                <div class="platform-cell">
                  <el-avatar :size="24" :src="getPlatformAvatar(scope.row.platform)" class="platform-avatar"></el-avatar>
                  <span class="platform-text">{{ getPlatformName(scope.row.platform) }}</span>
                </div>
              </template>
            </el-table-column>
            <el-table-column prop="status" label="授权状态" min-width="100" align="center">
              <template slot-scope="scope">
                <span :class="{'status-tag-success': scope.row.status, 'status-tag-danger': !scope.row.status}">
                   {{ getStatusLabel(scope.row.status) }}
                </span>
              </template>
            </el-table-column>
            <el-table-column prop="created_at" label="创建时间" min-width="180" align="center">
              <template slot-scope="scope">
                <span class="time-text">{{ formatDate(scope.row.created_at || scope.row.auth_time) }}</span>
              </template>
            </el-table-column>
            <!-- <el-table-column prop="updated_at" label="更新时间" min-width="180" align="center">
              <template slot-scope="scope">
                <span class="time-text">{{ formatDate(scope.row.updated_at || scope.row.auth_time) }}</span>
              </template>
            </el-table-column> -->
            <el-table-column label="操作" min-width="150" align="center">
              <template slot-scope="scope">
                <div class="table-action-buttons">
                  <el-button size="small" type="primary" @click="handleOpenAccount(scope.row)" class="table-action-button">
                    <i class="el-icon-view"></i>
                    登入
                  </el-button>
                  <el-button size="small" type="danger" @click="handleDelete(scope.row)" class="table-action-button">
                    <i class="el-icon-delete"></i>
                    删除
                  </el-button>
                </div>
              </template>
            </el-table-column>
          </el-table>

          <!-- 分页 -->
          <div class="pagination-wrapper">
            <el-pagination
              @size-change="handleSizeChange"
              @current-change="handleCurrentChange"
              :current-page="pagination.current"
              :page-sizes="[10, 20, 50, 100]"
              :page-size="pagination.size"
              layout="total, sizes, prev, pager, next, jumper"
              :total="pagination.total"
              class="account-pagination">
            </el-pagination>
          </div>
        </div>
      </div>
    </div>

    <!-- 新增账号授权弹窗 -->
    <el-dialog
      title="选择媒体平台"
      :visible.sync="addAccountDialogVisible"
      width="800px"
      center>
      <div class="platform-selection-grid">
        <div 
          v-for="platform in platforms" 
          :key="platform.platform_type"
          class="platform-selection-item"
          @click="selectPlatformForAuth(platform)">
          <div class="platform-selection-icon">
            <el-avatar :size="48" :src="platform.avatar"></el-avatar>
          </div>
          <div class="platform-selection-info">
            <h4 class="platform-selection-name">{{ platform.name }}</h4>
            <p class="platform-selection-desc">{{ getPlatformDescription(platform.platform_type) }}</p>
          </div>
        </div>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="addAccountDialogVisible = false">取消</el-button>
      </span>
    </el-dialog>

    <!-- Webview授权区域 -->
    <div v-if="src_url" class="webview-overlay">
      <!-- 关闭按钮放在webview外面顶部 -->
      <div class="webview-header">
        <div class="webview-title">
          <i class="el-icon-lock"></i>
          <span>{{ selectedPlatform ? selectedPlatform.name : '平台授权' }}</span>
        </div>
        <el-button 
          class="webview-close-btn" 
          type="danger" 
          size="small"
          @click="closeWebview">
          <i class="el-icon-close"></i>
          完成授权
        </el-button>
      </div>
      
      <webview 
        v-if="src_url" 
        :src="src_url"
        class="webview-container"
        :preload="preload"
        :partition="sessionPartition"
        useragent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/132.0.6834.111 Safari/537.3">
      </webview>
    </div>

    <!-- 发布功能 Drawer -->
    <el-drawer
      title="发布管理"
      :visible.sync="pushDrawerVisible"
      direction="rtl"
      size="80%">
      <Push />
    </el-drawer>
    
    <!-- 账号Webview弹窗 -->
    <div v-if="accountWebviewVisible" class="account-webview-overlay">
      <AccountWebview 
        :account-id="selectedAccountId"
        @close="closeAccountWebview"
      />
    </div>
  </div>
</template>

<script>
const { session } = require('@electron/remote')
import { AccountList, AccountCreate, AccountDelete, checkRule } from '@/api/index'
import { send_exe } from '@/api/push'

import { MediaPlatformList } from '@/api/plateform'
import { getScript } from '@/utils/index'
import request from '@/utils/request'
import { ipcRenderer } from "electron";
import { mediaLogin } from '@/api/push'
import Push from './push.vue'
import AccountWebview from './AccountWebview.vue'
export default {
  name: 'AccountList',
  components: {
    Push,
    AccountWebview
  },
  data() {
    return {
      loading: false,
      accountList: [],
      searchForm: {
        platform: '',
        account: '',
        name: '',
        status: ''
      },

      platforms: [],
      selectedPlatform: null,
      src_url: '',
      preload: '',
      webPreferences: 'nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=persist:session',
      // 授权登录过程中的状态
      postData: null,
      loginSuccess: false,
      sessionPartition: '',
      user: JSON.parse(localStorage.getItem("userInfo") || "{}"),
      platformOptions: [], // 初始化为空，后续通过 API 获取
      pagination: {
        current: 1,
        size: 10,
        total: 0
      },
      udid:'',
      uid:'',
      agent_ip_url:'',
      agent_ip_username:'',
      api_url:'',
      addAccountDialogVisible: false,
      selectedPlatform: '',
      pushDrawerVisible: false,
      accountWebviewVisible: false,
      selectedAccountId: null,
      sendArticleStatus: 0 // 发布按钮显示状态
    }
  },
  computed: {
    activeAccountsCount() {
      return this.accountList.filter(account => account.status === 'true').length;
    },
    filteredAccountList() {
      let filtered = this.accountList;
      
      // 按平台筛选
      if (this.searchForm.platform) {
        filtered = filtered.filter(account => account.platform === this.searchForm.platform);
      }
      

      
      // 按昵称筛选
      if (this.searchForm.name) {
        const keyword = this.searchForm.name.toLowerCase();
        filtered = filtered.filter(account => 
          (account.name && account.name.toLowerCase().includes(keyword)) ||
          (account.account && account.account.toLowerCase().includes(keyword))
        );
      }
      
      return filtered;
    }
  },

  activated(){
			this.$refs['multipleTable'].doLayout()
	},
  async mounted() {

    const userInfoStr = localStorage.getItem('userInfo'); // 获取字符串
    const userInfo = JSON.parse(userInfoStr); // 解析为对象

    this.udid = userInfo.udid; // 正确访问属性
    this.uid = userInfo.uid;
    console.log("UDID:", this.udid); // 正常输出 "1434
    // 异步获取平台配置
    try {
      await this.plateformList(); // 使用 plateformList 获取平台
    } catch (error) {
      console.error('获取平台配置失败:', error);
      this.$message.error('获取平台配置失败');
    }
    this.loadAccountList()
    this.get_send_exe()
    this.checkPublishStatus() // 检查发布状态
  },
  methods: {

    async get_send_exe() {
      try {
        // 调用新的统计接口
        const res = await send_exe({
          udid: this.udid,
          uid: this.uid
        });
        
        if (res && res.code === 1 && res.data) {
          const d = res.data
          this.agent_ip_username = d.agent_ip_username
          this.agent_ip_url = d.agent_ip_url
          this.api_url = d.api_url
          localStorage.setItem('api_url',this.api_url)
        }
      } catch (error) {
        console.error('获取首页信息失败:', error)
      }
    },
    open_proyx(){
      console.log("open proxy0",this.agent_ip_url)
      // 获取系统配置中的谷歌浏览器路径
      const systemConfig = localStorage.getItem('systemConfig')
      this.agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
      //使用本地代理进行覆盖，暂时不使用接口
      // if(this.agent_ip_url){
      //   console.log("open proxy success",this.agent_ip_url)
      //   ipcRenderer.send('proxyhandle',this.agent_ip_url)
      // }
      if(this.agent_ip_url){
        console.log("open proxy success",this.agent_ip_url)
        ipcRenderer.send('proxyhandle',this.agent_ip_url)
      }
    },

    // 选择平台
    async selectPlatform(platform) {
      this.selectedPlatform = platform
      await this.open_proyx()
      // 如果平台是 dy，则调用 Flask 服务器的授权接口
      if (platform.platform_type === 'dy' | platform.platform_type === 'bjh') {
        try {
          this.loading = true
          // 获取系统配置中的谷歌浏览器路径
          const systemConfig = localStorage.getItem('systemConfig')
          const googlePath = systemConfig ? JSON.parse(systemConfig).googlePath || '' : ''
          const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
          const agent_ip_username = systemConfig ? JSON.parse(systemConfig).agent_ip_username || '' : ''
          const data = {
            udid: this.udid,
            uid: this.uid,
            platform: platform.platform_type,
            agent_ip_url: agent_ip_url,
            agent_ip_username: agent_ip_username,
            googlePath: googlePath
          }
          
          const response = await mediaLogin(data)
          console.log("response",response)
          if (response && response.code==1) {
            this.$message.success('抖音授权成功')
            // 授权成功后刷新账号列表
            this.loadAccountList()
          } else {
            this.$message.error(response?.msg || '抖音授权失败')
          }
        } catch (error) {
          console.error('抖音授权失败:', error)
          this.$message.error(`抖音授权失败: ${error.message}`)
        } finally {
          this.loading = false
        }
      } else {
        // 其他平台使用原有的 webview 授权方式
        this.openPlatform()
      }
    },

    // 获取平台图标
    getPlatformIcon(type) {
      const iconMap = {
        tiktok: 'el-icon-video-camera',
        kuaishou: 'el-icon-video-play',
        red: 'el-icon-picture',
        sph: 'el-icon-video-camera'
      }
      return iconMap[type] || 'el-icon-platform'
    },



    // 打开平台授权
    async openPlatform(operate = 'checkLogin') {
      const item = this.selectedPlatform;
      // 初始化授权提交数据
      this.postData = {
        nickname: '',
        avatar: '',
        status: 'true',
        platform: item.platform_type,
        unique_id: "",
        cookie: "",
        state: "",
        follower_count: "",
        following_count: "",
        total_favorited: "",
        udid: this.udid,
        uid: this.uid
      }
      this.loginSuccess = false
      console.log("打开平台",item)
      this.preload = await getScript(item.platform_type)
      console.log("打开平台",this.preload)
      // 生成唯一的partition名称，确保每次都是新的会话
      const uniquePartition = `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      this.sessionPartition = `persist:${uniquePartition}`
      this.webPreferences = `nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=${this.sessionPartition}`;
      this.src_url = item.platform_ur;
      await this.$nextTick();
      const webview = document.querySelector("webview");

      webview.addEventListener("did-finish-load", (e) => {

        webview.addEventListener("ipc-message", (event) => {
          
          console.log(
            "收到登录成功的通讯了",
            event.channel,
            event.args[0]
          );
          if (event.channel == 'checkLogin' || event.channel == 'value') {
            if (this.postData && this.postData.nickname) return; // 已经接收到了数据，不再处理
            const data = event.args[0] || {};
            this.postData = {
              ...(this.postData || {}),
              nickname: data.name || '',
              avatar: data.avatar || '',
              cookie: data.cookie || (this.postData ? this.postData.cookie : ''),
              unique_id: data.account || '',
              follower_count: data.follower_count || '',
            }
            console.log("收到成功通知",this.postData)
            this.loginSuccess = 1
          }
        });
        webview.send(operate, { data: "主进程收到的消息，建立ipc-message链接" });
        // webview.openDevTools();
      });
    },

    // 保存平台账号
    async saveMeidaPlatform(data) {
      if (this.loading) return Promise.resolve();
      this.loading = true
      let promise;
      promise = AccountCreate(data)
      return promise.then((e) => {
        // promise.msg
        console.log("===66",e)
        this.$message.success(e.msg)
        
        this.loadAccountList()
      }).catch(() => {
        this.$message.error('授权失败')
        throw new Error('submit failed')
      }).finally(() => {
        this.loading = false
      })
    },

    // 关闭webview
    async closeWebview() {
      const webview = document.querySelector("webview");
      const hasLoginData = this.postData && this.loginSuccess == 1
      console.log("hasLoginData",hasLoginData)
      console.log("this.sessionPartition",this.sessionPartition)
      let finalPostData = null;
      
      // 检查是否有登录数据
      if (hasLoginData && this.sessionPartition) {
        try {
          // 读取当前 webview 分区中的所有 cookies
          const cookie = await session.fromPartition(this.sessionPartition).cookies.get({});
          console.log("获取到cookie", cookie);
          const encodedCookies = encodeURIComponent(JSON.stringify(cookie)); // ✅ 避免修改 const 常量
          console.log("cookie=====", encodedCookies);

          this.postData.cookie = encodedCookies;
          finalPostData = this.postData;
        } catch (e) {
          // 捕获异常处理优化
          console.error("Cookie 操作失败:", e); // ✅ 更清晰的错误日志
          this.$message.error(`授权失败: ${e.message}`); // ✅ 模板字符串整合错误信息
        }
      } else if (this.postData && this.sessionPartition) {
        // 授权失败，但有postData和sessionPartition，弹出二次弹窗让用户手动输入nickname
        console.log('触发二次弹窗逻辑');
        
        // 保存当前postData和sessionPartition的副本，防止后续被清空
        const postDataCopy = { ...this.postData };
        const sessionPartitionCopy = this.sessionPartition;

        // 读取当前 webview 分区中的所有 cookies
        const cookie = await session.fromPartition(sessionPartitionCopy).cookies.get({});
        const encodedCookies = encodeURIComponent(JSON.stringify(cookie));
        console.log("获取到cookie", cookie); 
        try {
          this.$prompt(
            '授权自动检测失败，如已登录成功，请手动输入账号昵称进行授权:',
            '授权确认',
            {
              confirmButtonText: '确认',
              cancelButtonText: '取消',
              inputPattern: /^[\S]+$/ // 不允许空字符串
            }
          ).then(async ({ value }) => {
            // 创建最终的提交数据，使用副本确保完整信息
            const finalData = {
              ...postDataCopy, // 使用保存的副本
              nickname: value,
              cookie: encodedCookies,
              status: 'true' // 手动输入昵称后默认为授权成功
            };
            
            console.log('最终提交数据:', finalData);
            
            // 直接调用saveMeidaPlatform保存数据
            try {
              await this.saveMeidaPlatform(finalData);
              // this.$message.success('授权成功');
            } catch (saveError) {
              console.error("保存媒体平台失败:", saveError);
              this.$message.error(`保存失败: ${saveError.message}`);
            }
          }).catch(() => {
            console.log('用户取消了手动授权');
            this.$message.info('已取消授权');
          });
        } catch (e) {
          console.error("二次弹窗处理失败:", e);
        }
      } else {
        this.$message.error('授权失败，未登录成功')
      }
      
      // 注意：当走二次弹窗逻辑时，finalPostData不会在这里保存，而是在弹窗确认后直接保存
      // 这里只处理自动授权成功的情况
      if (finalPostData && hasLoginData) {
        try {
          await this.saveMeidaPlatform(finalPostData);
        } catch (e) {
          console.error("保存媒体平台失败:", e);
          this.$message.error(`保存失败: ${e.message}`);
        }
      }
      
      // 不再手动移除webview，而是通过重置状态让Vue处理
      if (webview) {
        try {
          // 使用 session 来清理缓存和数据
          if (this.sessionPartition) {
            const sessionInstance = session.fromPartition(this.sessionPartition);
            
            // 清除缓存
            sessionInstance.clearCache().then(() => {
              console.log('缓存已清除');
            }).catch(err => {
              console.error('清除缓存失败:', err);
            });
            
            // 清除存储数据
            sessionInstance.clearStorageData({
              storages: ['appcache', 'cookies', 'filesystem', 'indexdb', 'localstorage', 
                        'shadercache', 'websql', 'serviceworkers', 'cachestorage'],
            }).then(() => {
              console.log('存储数据已清除');
            }).catch(err => {
              console.error('清除存储数据失败:', err);
            });
          }
        } catch (error) {
          console.error('清理 Webview 失败:', error);
        }
      }

      // 清理 Session 分区
      // if (this.sessionPartition) {
      //   try {
      //     const sessionInstance = session.fromPartition(this.sessionPartition.replace('persist:', ''));
          
      //     // 使用新的API清理session
      //     await sessionInstance.clearCache();
      //     await sessionInstance.clearStorageData({
      //       storages: ['appcache', 'cookies', 'filesystem', 'indexdb', 'localstorage', 
      //                 'shadercache', 'websql', 'serviceworkers', 'cachestorage'],
      //     });
      //     console.log('Session 已清理');
      //   } catch (error) {
      //     console.error('清理 Session 失败:', error);
      //   }
      // }
      this.src_url = ''
      this.selectedPlatform = null
      this.postData = null
      this.loginSuccess = false
      this.sessionPartition = ''
      console.log("关闭webview",this.src_url)
    },

    // 加载账号列表
    async loadAccountList() {
      this.loading = true
      try {
        const params = {
          page: this.pagination.current,
          size: this.pagination.size,
          udid: this.udid,
          uid: this.uid,
          ...this.searchForm
        }
        const response = await AccountList(params)
        if (response.data) {
          this.accountList = response.data.user_list || []
          this.pagination.total = response.data.total_count || 0
        }
      } catch (error) {
        this.$message.error('加载账号列表失败')
        console.error('加载账号列表失败:', error)
      } finally {
        this.loading = false
      }
    },

    async plateformList() {
      let params = {udid:this.udid,uid:this.uid}
      const response = await MediaPlatformList(params)
      if (response.data) {
        this.platforms = response.data
        console.log(this.platforms)
        // 设置 platformOptions 用于搜索下拉
        this.platformOptions = response.data.map(item => ({
          label: item.name,
          value: item.platform_type
        }))
      }
    },

    // 搜索
    handleSearch() {
      this.pagination.current = 1
      this.loadAccountList()
    },

    // 重置搜索
    handleReset() {
      this.searchForm = {
        platform: '',
        account: '',
        name: '',
        status: ''
      }
      this.pagination.current = 1
      this.loadAccountList()
    },



    // 刷新授权
    async handleRefresh(row) {
      try {
        await this.$confirm('确定要刷新该账号的授权吗？', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        })
        
        // 这里应该调用刷新授权的API
        this.$message.success('授权刷新成功')
        this.loadAccountList()
      } catch (error) {
        if (error !== 'cancel') {
          this.$message.error('刷新授权失败')
        }
      }
    },

    // 打开账号
    async handleOpenAccount(row) {
      // 将账号数据存储到localStorage，供webview组件使用

      const accountList = this.accountList
      localStorage.setItem('accountList', JSON.stringify(accountList))
      this.selectedAccountId = row.id
      this.accountWebviewVisible = true
    },
    
    // 关闭账号webview
    closeAccountWebview() {
      this.accountWebviewVisible = false
      this.selectedAccountId = null
    },

    // 删除账号
    async handleDelete(row) {
      try {
        await this.$confirm('确定要删除该账号吗？', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        })
        
        await AccountDelete({ juzhen_user_id: row.juzhen_user_id,udid:this.udid,uid:this.uid })
        this.$message.success('删除成功')
        this.loadAccountList()
      } catch (error) {
        if (error !== 'cancel') {
          this.$message.error('删除失败')
        }
      }
    },

    // 分页处理
    handleSizeChange(val) {
      this.pagination.size = val
      this.loadAccountList()
    },

    handleCurrentChange(val) {
      this.pagination.current = val
      this.loadAccountList()
    },



    // 获取平台标签文本
    getPlatformLabel(platform) {
      const labelMap = {
        tiktok: '抖音',
        kuaishou: '快手',
        red: '小红书',
        sph: '视频号',
        bjh:'bjh'
      }
      return labelMap[platform] || platform
    },

    // 根据平台类型获取平台头像
    getPlatformAvatar(platformType) {
      const platform = this.platforms.find(p => p.platform_type === platformType)
      return platform ? platform.avatar : ''
    },

    // 根据平台类型获取平台名称
    getPlatformName(platformType) {
      const platform = this.platforms.find(p => p.platform_type === platformType)
      return platform ? platform.name : platformType
    },

    // 获取状态标签类型
    getStatusTagType(status) {
      const typeMap = {
        'true': 'success',
        'false': 'danger',
      }
      return typeMap[status] || 'info'
    },

    // 获取状态标签文本
    getStatusLabel(status) {
      const labelMap = {
        'true': '已授权',
        'false': '授权过期'
      }
      return labelMap[status] || status
    },

    // 格式化日期
    formatDate(date) {
      if (!date) return '-'
      return new Date(date).toLocaleString()
    },
    
    // 获取平台描述
    getPlatformDescription(platformType) {
      const descriptionMap = {
        tiktok: '抖音短视频平台',
        kuaishou: '快手短视频平台',
        red: '小红书内容平台',
        sph: '微信视频号',
        bjh: '百度百家号',
        tt: '今日头条',
        dy: '抖音创作者',
        xhs: '小红书创作者',
        csdn: 'CSDN技术社区',
        zh: '知乎问答平台',
        wxgzh: '微信公众号',
        bili: '哔哩哔哩视频平台',
        wy: '网易号',
        js: '简书创作平台',
        qeh: '腾讯企鹅号',
        sh: '搜狐号'
      }
      return descriptionMap[platformType] || '内容创作平台'
    },
    
    // 刷新账号列表
    refreshAccounts() {
      this.loadAccountList()
    },
    
    // 获取平台账号数量
    getPlatformAccountCount(platformType) {
      return this.accountList.filter(account => account.platform === platformType).length;
    },
    
    // 按平台筛选账号
    filterByPlatform(platformType) {
      if (this.selectedPlatform === platformType) {
        // 取消选中，查询全部
        this.selectedPlatform = '';
        this.searchForm.platform = '';
      } else {
        // 选中平台
        this.selectedPlatform = platformType;
        this.searchForm.platform = platformType;
      }
      this.pagination.current = 1;
      this.loadAccountList();
    },
    
    // 打开新增账号授权弹窗
    openAddAccountDialog() {
      this.addAccountDialogVisible = true;
    },
    
    // 选择平台进行授权
    selectPlatformForAuth(platform) {
      this.addAccountDialogVisible = false;
      this.selectPlatform(platform);
    },
    
    // 打开发布功能 Drawer
    openPushDrawer() {
      this.pushDrawerVisible = true;
    },
    
    async checkPublishStatus() {
      try {
        const response = await checkRule({ udid: this.udid, uid: this.uid })
        if (response && response.code === 1 && response.data) {
          console.log('发布状态:', response.data)
          this.sendArticleStatus = response.data.send_article_status
          console.log('发布状态:', this.sendArticleStatus)
        }
      } catch (error) {
        console.error('获取发布状态失败:', error)
      }
    }
  }
}
</script>

