<template>
  <div class="account-webview">
    <div class="webview-header">
      <div class="webview-title">
        <!-- <span>{{ platformName }}</span> -->
      </div>
      
      <!-- 添加导航按钮组 -->
      <div class="webview-nav-buttons">
        <el-button 
          class="nav-btn" 
          type="primary" 
          size="small"
          :disabled="!canGoBack"
          @click="goBack">
          <i class="el-icon-arrow-left"></i>
          后退
        </el-button>
        
        <el-button 
          class="nav-btn" 
          type="primary" 
          size="small"
          :disabled="!canGoForward"
          @click="goForward">
          <i class="el-icon-arrow-right"></i>
          前进
        </el-button>
        
        <el-button 
          class="nav-btn" 
          type="success" 
          size="small"
          @click="refresh">
          <i class="el-icon-refresh"></i>
          刷新
        </el-button>
      </div>
      
      <el-button 
        class="webview-close-btn" 
        type="danger" 
        size="small"
        @click="closeWebview">
        <i class="el-icon-close"></i>
        关闭
      </el-button>
    </div>
    
    <!-- 添加加载状态显示 -->
    <div v-if="isLoading" class="loading-container">
      <div class="loading-content">
        <i class="el-icon-loading"></i>
        <p>正在准备登录状态...</p>
      </div>
    </div>
    
    <webview 
      v-if="webviewUrl && !isLoading" 
      :src="webviewUrl"
      class="webview-container"
      allowpopups
      :partition="`persist:${currentPartition}`"
      webpreferences="nodeIntegration=false, contextIsolation=true, webSecurity=true">
    </webview>
  </div>
</template>

<script>
const { session } = require('@electron/remote')
import { ipcRenderer } from "electron";
import { MediaPlatformList } from '@/api/plateform'

export default {
  name: 'AccountWebview',
  props: {
    accountId: {
      type: [String, Number],
      required: true
    }
  },
  data() {
    return {
      webviewUrl: '',
      platformName: '',
      accountData: null,
      platforms: [],
      currentPartition: '',
      isLoading: true, // 添加加载状态
      webviewElement: null, // 添加webview元素引用
      canGoBack: false, // 是否可以后退
      canGoForward: false, // 是否可以前进
      platformUrlMap: {
        'bjh': 'https://baijiahao.baidu.com/builder/rc/home',
        'tt': 'https://mp.toutiao.com/profile_v4/index',
        'dy': 'https://creator.douyin.com/creator-micro/content/upload',
        'kuaishou': 'https://cp.kuaishou.com',
        'xhs': 'https://creator.xiaohongshu.com',
        'sph': 'https://channels.weixin.qq.com',
        'qeh': 'https://om.qq.com/main',
        'zh': 'https://www.zhihu.com/',
        'wxgzh': 'https://mp.weixin.qq.com/cgi-bin/home',
        'bili':'https://www.bilibili.com/',
        'csdn': 'https://www.csdn.net/',
        'sh': 'https://mp.sohu.com/mpfe/v4/contentManagement/first/page',
        'wy':'https://mp.163.com/subscribe_v4/index.html#/article-publish',
        'js':'https://www.jianshu.com/'
      }
    }
  },
  async mounted() {
    if (this.accountId) {
      // 加载平台配置
      await this.loadPlatforms()
      // 加载账号数据
      await this.loadAccountData(this.accountId)
    } else {
      this.$message.error('缺少账号ID参数')
      this.closeWebview()
    }
  },
  methods: {
    async loadPlatforms() {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo') || '{}')
        const params = { udid: userInfo.udid, uid: userInfo.uid }
        const response = await MediaPlatformList(params)
        if (response.data) {
          this.platforms = response.data
          console.log('加载平台配置:', this.platforms)
        }
      } catch (error) {
        console.error('加载平台配置失败:', error)
      }
    },

    async loadAccountData(accountId) {
      try {
        const accountListStr = localStorage.getItem('accountList')
        console.log('从localStorage获取的账号列表字符串:', accountListStr)
        
        const accountList = JSON.parse(accountListStr || '[]')
        console.log('解析后的账号列表:', accountList)
        
        this.accountData = accountList.find(account => account.id == accountId)
        
        if (this.accountData) {
          console.log('找到账号数据:', this.accountData)
          await this.setupWebview()
        } else {
          console.error('未找到账号数据，accountId:', accountId)
          console.log('所有账号ID:', accountList.map(acc => acc.id))
          this.$message.error('账号信息不存在')
          this.closeWebview()
        }
      } catch (error) {
        console.error('加载账号数据失败:', error)
        this.$message.error('加载账号数据失败')
        this.closeWebview()
      }
    },

    async setupWebview() {
      // 设置代理
      await this.open_proyx()
      
      // 等待代理设置生效
      await new Promise(resolve => setTimeout(resolve, 500))
      
      const platform = this.accountData.platform
      console.log('平台类型:', platform)
      
      // 尝试从平台配置中获取URL
      let baseUrl = null
      // if (this.platforms.length > 0) {
      //   const platformConfig = this.platforms.find(p => p.platform_type === platform)
      //   if (platformConfig && platformConfig.platform_ur) {
      //     baseUrl = platformConfig.platform_ur
      //     console.log('从平台配置获取URL:', baseUrl)
      //   }
      // }
      
      // 如果平台配置中没有URL，使用默认映射
      if (!baseUrl) {
        baseUrl = this.platformUrlMap[platform]
        console.log('使用默认URL映射:', baseUrl)
      }
      
      if (!baseUrl) {
        this.$message.error(`不支持的平台类型: ${platform}`)
        this.closeWebview()
        return
      }


      console.log('准备URL:', baseUrl)
      
      const uniquePartition = `account_session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
      this.currentPartition = uniquePartition
      
      // 设置 session 级别的 User-Agent
      try {
        const sessionInstance = session.fromPartition(`persist:${uniquePartition}`);
        sessionInstance.setUserAgent("Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.4389.90 Safari/537.36");
        console.log("已设置 session User-Agent");
      } catch (error) {
        console.error("设置 session User-Agent 失败:", error);
      }
      
      // 先注入cookies，然后再显示webview
      await this.preInjectCookies(baseUrl)
      
      // 注入完成后，设置URL并显示webview
      this.webviewUrl = baseUrl
      this.isLoading = false
      
      await this.$nextTick()
      
      const webview = document.querySelector("webview")
      if (webview) {
        // 保存webview元素引用
        this.webviewElement = webview
        
        // webview.openDevTools();
        // 添加错误处理
        webview.addEventListener("did-fail-load", (event) => {
          console.error('Webview加载失败:', event)
        })
        
        webview.addEventListener("new-window", (e) => {
          console.log("处理点击点击事件")
          webview.src = e.url;
        });

        webview.addEventListener("did-finish-load", (event) => {
          // console.error('Webview加载失败:', event)
          // webview.openDevTools();
          
          // 尝试覆盖 User-Agent
          setTimeout(async () => {
            try {
              await webview.executeJavaScript(`
                // 尝试覆盖 navigator.userAgent
                Object.defineProperty(navigator, 'userAgent', {
                  value: 'Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.4389.90 Safari/537.36',
                  writable: false,
                  configurable: false
                });
                
                // 尝试覆盖 navigator.platform
                Object.defineProperty(navigator, 'platform', {
                  value: 'Win32',
                  writable: false,
                  configurable: false
                });
                
                console.log('已尝试覆盖 User-Agent:', navigator.userAgent);
              `);
            } catch (e) {
              console.log("覆盖 User-Agent 失败:", e);
            }
          }, 1000);
          
          // 更新导航状态
          this.updateNavigationState();
        })
        
        // 监听导航状态变化
        webview.addEventListener("did-navigate", (event) => {
          this.updateNavigationState();
        })
        
        webview.addEventListener("did-navigate-in-page", (event) => {
          this.updateNavigationState();
        })
            
        // webview.addEventListener("console-message", (event) => {
        //   console.log('Webview console:', event.message)
        // })
      }
    },

    async preInjectCookies(baseUrl) {
      if (!this.accountData.cookies) {
        console.log('账号没有cookie信息')
        return
      }

      try {
        console.log('开始预注入cookies...')
        console.log('原始cookie数据:', this.accountData.cookies)
        const cookieString = decodeURIComponent(this.accountData.cookies)
        const cookies = JSON.parse(cookieString)
        
        console.log('解析后的cookies:', cookies)
        
        // 使用@electron/remote获取session
        const webviewSession = session.fromPartition(`persist:${this.currentPartition}`)
        
        // 从URL中提取域名
        const urlObj = new URL(baseUrl)
        const baseDomain = urlObj.hostname
        console.log('baseDomain:', baseDomain)
        let injectedCount = 0
        for (const cookie of cookies) {
          try {
            // 清理和验证cookie数据
            const sanitizedCookie = this.sanitizeCookie(cookie)
            if (!sanitizedCookie) {
              console.warn(`跳过无效cookie: ${cookie.name || 'unknown'}`)
              continue
            }
            
            // 验证和清理domain值
            let domain = sanitizedCookie.domain || ''
            
            // 如果domain以点开头，去掉开头的点
            if (domain.startsWith('.')) {
              domain = domain.substring(1)
            }
            
            // 如果domain为空或无效，使用URL的hostname
            if (!domain || domain === 'null' || domain === 'undefined') {
              domain = baseDomain
            }
            
            // 确保domain是有效的
            if (!this.isValidDomain(domain)) {
              console.warn(`跳过无效domain的cookie: ${sanitizedCookie.name}, domain: ${domain}`)
              continue
            }
            
            const cookieData = {
              url: baseUrl,
              name: sanitizedCookie.name,
              value: sanitizedCookie.value,
              path: sanitizedCookie.path,
              secure: sanitizedCookie.secure,
              httpOnly: sanitizedCookie.httpOnly
            }
            
            // 只有当domain有效且不为空时才添加domain属性
            if (domain && domain !== baseDomain) {
              cookieData.domain = domain
            }
            
            // 只有当expirationDate存在且有效时才添加
            if (sanitizedCookie.expirationDate) {
              cookieData.expirationDate = sanitizedCookie.expirationDate
            }
            
            await webviewSession.cookies.set(cookieData)
            injectedCount++
            console.log(`成功注入cookie: ${sanitizedCookie.name}`)
          } catch (error) {
            console.warn('注入cookie失败:', cookie.name || 'unknown', error.message)
          }
        }
        
        console.log(`Cookie预注入完成，成功注入 ${injectedCount} 个cookie`)
        
        // 等待一小段时间确保cookie设置完成
        await new Promise(resolve => setTimeout(resolve, 500))
        
      } catch (error) {
        console.error('预注入cookie失败:', error)
        this.$message.warning('Cookie注入失败，可能需要重新登录')
      }
    },

  
    isValidDomain(domain) {
      if (!domain || typeof domain !== 'string') {
        return false
      }
      
      // 过滤掉明显的无效值
      if (domain === 'null' || domain === 'undefined' || domain === '' || domain === 'localhost') {
        return false
      }
      
      // 基本的域名验证 - 更宽松的规则
      const domainRegex = /^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/
      return domainRegex.test(domain)
    },

    // 清理和验证cookie数据
    sanitizeCookie(cookie) {
      const sanitized = { ...cookie }
      
      // 确保必要字段存在
      if (!sanitized.name || !sanitized.value) {
        return null
      }
      
      // 清理name和value
      sanitized.name = String(sanitized.name).trim()
      sanitized.value = String(sanitized.value).trim()
      
      if (!sanitized.name || !sanitized.value) {
        return null
      }
      
      // 设置默认值
      sanitized.path = sanitized.path || '/'
      sanitized.secure = Boolean(sanitized.secure)
      sanitized.httpOnly = Boolean(sanitized.httpOnly)
      
      return sanitized
    },



    closeWebview() {
      this.$emit('close')
    },

    // 刷新webview
    refresh() {
      if (this.webviewElement) {
        this.webviewElement.reload();
      }
    },

    // 后退
    goBack() {
      if (this.webviewElement) {
        this.webviewElement.goBack();
      }
    },

    // 前进
    goForward() {
      if (this.webviewElement) {
        this.webviewElement.goForward();
      }
    },

    // 更新导航状态
    updateNavigationState() {
      if (this.webviewElement) {
        this.canGoBack = this.webviewElement.canGoBack();
        this.canGoForward = this.webviewElement.canGoForward();
      }
    },
    
    // 设置代理
    async open_proyx() {
      console.log("open proxy0")
      const systemConfig = localStorage.getItem('systemConfig')
      const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
      if(agent_ip_url){
        console.log("open proxy success", agent_ip_url)
        ipcRenderer.send('proxyhandle', agent_ip_url)
      }
    }
  }
}
</script>

<style scoped lang="css">
.account-webview {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: var(--bg-primary);
  z-index: 9999;
  display: flex;
  flex-direction: column;
}

.webview-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 20px;
  background-color: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  z-index: 10000;
  min-height: 60px;
}

.webview-title {
  font-size: 18px;
  font-weight: bold;
  color: var(--text-primary);
}

.webview-close-btn {
  z-index: 10000;
}

.webview-nav-buttons {
  display: flex;
  gap: 8px; /* 按钮之间的间距 */
  margin-right: 15px; /* 与关闭按钮的间距 */
  align-items: center;
}

.nav-btn {
  padding: 6px 12px;
  font-size: 13px;
  border-radius: 4px;
}

.nav-btn i {
  margin-right: 4px;
}

.webview-container {
  flex: 1;
  width: 100%;
  height: calc(100% - 60px);
}

/* 新增加载状态样式 */
.loading-container {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  background-color: var(--bg-primary);
}

.loading-content {
  text-align: center;
  color: var(--text-secondary);
}

.loading-content i {
  font-size: 40px;
  margin-bottom: 10px;
  color: #3b82f6; /* 使用Element UI的主题色 */
  animation: rotate 2s linear infinite;
}

.loading-content p {
  font-size: 16px;
  margin: 0;
  color: var(--text-secondary);
}

@keyframes rotate {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}
</style> 