<template>
    <div class="login-page">
        <!-- 背景动画 -->
        <div class="background-animation">
            <div class="gradient-bg"></div>
            <div class="floating-shapes">
                <div class="shape shape-1"></div>
                <div class="shape shape-2"></div>
                <div class="shape shape-3"></div>
                <div class="shape shape-4"></div>
                <div class="shape shape-5"></div>
            </div>
        </div>

        <!-- 登录容器 -->
        <div class="login-container">
            <div class="login-card">
                <!-- Logo区域 -->
                <div class="logo-section">
                    <p class="app-subtitle">授权小助手</p>
                </div>
                
                <!-- 实例信息 -->
                <!-- <div class="instance-info" v-if="instanceCount > 0">
                    <el-alert
                        :title="`当前运行实例数量: ${instanceCount}`"
                        type="info"
                        :closable="false"
                        show-icon>
                    </el-alert>
                </div> -->

                <!-- 登录表单 -->
                <div class="form-container">
                    <el-form 
                        ref="loginForm" 
                        :model="loginForm" 
                        :rules="loginRules" 
                        class="login-form"
                    >
                        <div class="input-group">
                            <div class="input-wrapper">
                                <i class="el-icon-user input-icon"></i>
                                <el-input
                                    v-model="loginForm.username"
                                    placeholder="请输入用户名"
                                    class="custom-input"
                                    size="large"
                                />
                            </div>
                        </div>
                        
                        <div class="input-group">
                            <div class="input-wrapper">
                                <i class="el-icon-lock input-icon"></i>
                                <el-input
                                    v-model="loginForm.password"
                                    type="password"
                                    placeholder="请输入密码"
                                    class="custom-input"
                                    size="large"
                                    show-password
                                />
                            </div>
                        </div>

                        
                        <div class="input-group">
                            <div class="input-wrapper">
                                <i class="el-icon-user input-icon"></i>
                                <el-input
                                    v-model="loginForm.udid"
                                    placeholder="请输入授权码"
                                    class="custom-input"
                                    size="large"
                                />
                            </div>
                        </div>

                        <div class="form-options">
                            <el-checkbox v-model="rememberMe">记住我</el-checkbox>
                            <a href="#" class="forgot-password" @click.prevent="clearSavedLoginData">清除保存的登录信息</a>
                        </div>

                        <div class="terms-agreement">
                            <el-checkbox v-model="agreeToTerms">
                                登录视为您已阅读并同意
                                <span class="terms-link" @click="openTerms">《用户协议》</span>
                            </el-checkbox>
                        </div>

                        <el-button 
                            type="primary" 
                            @click="handleLogin"
                            class="submit-btn"
                            :loading="loading"
                            size="large"
                        >
                            <span v-if="!loading">登录</span>
                            <span v-else>登录中...</span>
                        </el-button>
                    </el-form>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import request from "@/utils/request";
import { setToken } from '@/utils/auth.js';
import { shell,ipcRenderer  } from 'electron';

export default {
    name: 'LoginPage',
    data() {
        return {
            loading: false,
            rememberMe: false,
            agreeToTerms: false,
            instanceCount: 0,
            
            // 登录表单
            loginForm: {
                username: '',
                password: '',
                udid:'',
                instanceCount:0
            },
            
            // 登录验证规则
            loginRules: {
                username: [
                    { required: true, message: '请输入用户名', trigger: 'blur' },
                    { min: 3, max: 20, message: '用户名长度在 3 到 20 个字符', trigger: 'blur' }
                ],
                password: [
                    { required: true, message: '请输入密码', trigger: 'blur' },
                    { min: 6, max: 20, message: '密码长度在 6 到 20 个字符', trigger: 'blur' }
                ],
                udid: [
                    { required: true, message: '请输入授权码', trigger: 'blur' },
                    { min: 6, max: 20, message: '密码长度在 6 到 20 个字符', trigger: 'blur' }
                ],
                
            }
        };
    },
    
    mounted() {
        // 组件挂载时加载保存的登录数据
        this.loadSavedLoginData();
        // 获取实例数量
        this.getInstanceCount();

    },
    
    methods: {
        // 获取实例数量
        async getInstanceCount() {
            try {
                const instanceCount = await ipcRenderer.invoke('get-instance-count');
                console.log('当前实例数量:', instanceCount);
                this.instanceCount = instanceCount;
                this.loginForm.instanceCount = instanceCount
            } catch (error) {
                console.error('获取实例数量失败:', error);
            }
        },
        
        // 加载保存的登录数据
        loadSavedLoginData() {
            try {
                const savedData = localStorage.getItem('savedLoginData');
                if (savedData) {
                    const parsedData = JSON.parse(savedData);
                    
                    // 检查数据是否过期（30天）
                    const thirtyDaysInMs = 30 * 24 * 60 * 60 * 1000;
                    const isExpired = parsedData.timestamp && 
                        (new Date().getTime() - parsedData.timestamp > thirtyDaysInMs);
                    
                    if (isExpired) {
                        // 数据已过期，清除它
                        localStorage.removeItem('savedLoginData');
                        return;
                    }
                    
                    this.loginForm.username = parsedData.username || '';
                    this.loginForm.password = parsedData.password || '';
                    this.loginForm.udid = parsedData.udid || '';
                    this.rememberMe = true;
                }
            } catch (error) {
                console.error('加载保存的登录数据失败:', error);
                // 如果解析失败，清除损坏的数据
                localStorage.removeItem('savedLoginData');
            }
        },
        
        // 保存登录数据
        saveLoginData() {
            if (this.rememberMe) {
                try {
                    const dataToSave = {
                        username: this.loginForm.username,
                        password: this.loginForm.password,
                        udid: this.loginForm.udid,
                        timestamp: new Date().getTime()
                    };
                    localStorage.setItem('savedLoginData', JSON.stringify(dataToSave));
                    
                } catch (error) {
                    console.error('保存登录数据失败:', error);
                }
            } else {
                // 如果未勾选记住我，清除保存的数据
                localStorage.removeItem('savedLoginData');
            }
        },
        
        // 清除保存的登录数据
        clearSavedLoginData() {
            this.$confirm('确定要清除保存的登录信息吗？', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).then(() => {
                localStorage.removeItem('savedLoginData');
                this.loginForm.username = '';
                this.loginForm.password = '';
                this.loginForm.udid = '';
                this.rememberMe = false;
                this.$message.success('已清除保存的登录信息');
            }).catch(() => {
                // 用户取消操作
            });
        },
        
        openTerms() {
            shell.openExternal('https://my.feishu.cn/wiki/FKSFw27hSiUWtkkN5OMcmnmPnMb');
        },
        
        async handleLogin() {
            try {
                const valid = await this.$refs.loginForm.validate();
                if (!valid) return;
                
                // 验证协议勾选
                if (!this.agreeToTerms) {
                    this.$message.error('请勾选用户协议');
                    return;
                }
                
                this.loading = true;
                
                // // 模拟登录请求
                // setTimeout(() => {
                //     setToken("====");
                //     this.$message.success('登录成功！');
                //     this.$router.push('/');
                //     this.loading = false;
                // }, 1000);
                
                // 实际登录逻辑
                const response = await request.post("/api/zhushou/login", this.loginForm);
                
                // 检查登录响应是否成功
                if (response && response.data) {
                    setToken(response.data);
                    localStorage.setItem('userInfo', JSON.stringify(response.data));
                    
                    // 保存登录数据（如果勾选了记住我）
                    this.saveLoginData();
                    
                    this.$message.success('登录成功！');
                    this.$router.push('/');
                } else {
                    // 登录响应无效
                    this.$message.error(response.msg);
                }
                
            } catch (error) {
                console.error('登录错误:', error);
                this.$message.error('登录失败，请重试');
                // 登录失败时不清除表单，让用户可以重新尝试
            } finally {
                this.loading = false;
            }
        }
    }
};
</script>

<style scoped lang="scss">
.login-page {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
    background: var(--bg-primary);
}

// 背景动画
.background-animation {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1;
}

.gradient-bg {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--gradient-secondary);
    animation: gradientShift 8s ease-in-out infinite;
}

.floating-shapes {
    position: absolute;
    width: 100%;
    height: 100%;
}

.shape {
    position: absolute;
    border-radius: 50%;
    background: rgba(0, 122, 255, 0.1);
    animation: float 6s ease-in-out infinite;
    backdrop-filter: blur(10px);
    
    &.shape-1 {
        width: 80px;
        height: 80px;
        top: 20%;
        left: 10%;
        animation-delay: 0s;
    }
    
    &.shape-2 {
        width: 120px;
        height: 120px;
        top: 60%;
        right: 10%;
        animation-delay: 2s;
    }
    
    &.shape-3 {
        width: 60px;
        height: 60px;
        top: 80%;
        left: 20%;
        animation-delay: 4s;
    }
    
    &.shape-4 {
        width: 100px;
        height: 100px;
        top: 10%;
        right: 30%;
        animation-delay: 1s;
    }
    
    &.shape-5 {
        width: 40px;
        height: 40px;
        top: 40%;
        left: 60%;
        animation-delay: 3s;
    }
}

// 登录容器
.login-container {
    position: relative;
    z-index: 2;
    width: 100%;
    max-width: 450px;
    padding: 20px;
}

.login-card {
    background: var(--bg-card);
    backdrop-filter: blur(20px);
    border-radius: var(--radius-xl);
    padding: 40px;
    box-shadow: var(--shadow-lg);
    border: 1px solid var(--border-color);
    position: relative;
    overflow: hidden;
    
    &::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        height: 3px;
        background: var(--gradient-primary);
    }
}

// Logo区域
.logo-section {
    text-align: center;
    margin-bottom: 30px;
}

// 实例信息
.instance-info {
    margin-bottom: 20px;
    
    :deep(.el-alert) {
        border-radius: var(--radius-md);
        border: 1px solid var(--border-color);
        background: var(--bg-tertiary);
        
        .el-alert__title {
            color: var(--text-primary);
            font-weight: 500;
        }
        
        .el-alert__icon {
            color: var(--primary-color);
        }
    }
}

.logo {
    width: 80px;
    height: 80px;
    margin: 0 auto 20px;
    background: var(--gradient-primary);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 10px 30px rgba(0, 122, 255, 0.3);
    
    i {
        font-size: 36px;
        color: white;
    }
}

.app-title {
    font-size: 28px;
    font-weight: 700;
    color: var(--text-primary);
    margin: 0 0 8px;
    font-family: 'Orbitron', sans-serif;
    text-transform: uppercase;
    letter-spacing: 1px;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.app-subtitle {
    font-size: 20px;
    font-weight: 600;
    color: #303133;
    margin: 0;
    font-family: 'Orbitron', sans-serif;
    letter-spacing: 0.5px;
    text-align: center;
    padding: 10px 0;
}

// 表单区域
.form-container {
    margin-bottom: 30px;
}

.input-group {
    margin-bottom: 20px;
}

.input-wrapper {
    position: relative;
    
    .input-icon {
        position: absolute;
        left: 16px;
        top: 50%;
        transform: translateY(-50%);
        color: var(--text-muted);
        font-size: 18px;
        z-index: 2;
    }
}

.custom-input {
    :deep(.el-input__inner) {
        height: 50px;
        padding-left: 50px;
        border-radius: var(--radius-md);
        border: 2px solid var(--border-color);
        background: var(--bg-tertiary);
        transition: all 0.3s ease;
        font-size: 14px;
        color: var(--text-primary);
        
        &:focus {
            border-color: var(--primary-color);
            background: var(--bg-card);
            box-shadow: 0 0 0 3px rgba(0, 122, 255, 0.1);
        }
        
        &::placeholder {
            color: var(--text-muted);
        }
    }
}

.form-options {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 25px;
    font-size: 14px;
    
    .forgot-password {
        color: var(--primary-color);
        text-decoration: none;
        transition: color 0.3s ease;
        
        &:hover {
            color: var(--primary-light);
        }
    }
    
    :deep(.el-checkbox__label) {
        color: var(--text-secondary);
    }
    
    :deep(.el-checkbox__input.is-checked .el-checkbox__inner) {
        background-color: var(--primary-color);
        border-color: var(--primary-color);
    }
}

.terms-agreement {
    margin-bottom: 25px;
    font-size: 14px;
    text-align: center;
    
    :deep(.el-checkbox__label) {
        color: var(--text-secondary);
        line-height: 1.4;
    }
    
    :deep(.el-checkbox__input.is-checked .el-checkbox__inner) {
        background-color: var(--primary-color);
        border-color: var(--primary-color);
    }
    
    .terms-link {
        color: var(--primary-color);
        text-decoration: none;
        transition: color 0.3s ease;
        
        &:hover {
            color: var(--primary-light);
            text-decoration: underline;
        }
    }
}

.submit-btn {
    width: 100%;
    height: 50px;
    border-radius: var(--radius-md);
    font-size: 16px;
    font-weight: 600;
    background: var(--gradient-primary);
    border: none;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
    
    &::before {
        content: '';
        position: absolute;
        top: 0;
        left: -100%;
        width: 100%;
        height: 100%;
        background: linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent);
        transition: left 0.5s ease;
    }
    
    &:hover {
        transform: translateY(-2px);
        box-shadow: 0 10px 25px rgba(0, 122, 255, 0.3);
        
        &::before {
            left: 100%;
        }
    }
    
    &:active {
        transform: translateY(0);
    }
}

// 动画
@keyframes gradientShift {
    0%, 100% {
        background-position: 0% 50%;
    }
    50% {
        background-position: 100% 50%;
    }
}

@keyframes float {
    0%, 100% {
        transform: translateY(0px) rotate(0deg);
    }
    50% {
        transform: translateY(-20px) rotate(180deg);
    }
}

// 响应式设计
@media (max-width: 768px) {
    .login-container {
        padding: 10px;
    }
    
    .login-card {
        padding: 30px 20px;
    }
    
    .app-title {
        font-size: 24px;
    }
    
    .logo {
        width: 60px;
        height: 60px;
        
        i {
            font-size: 28px;
        }
    }
}
</style>