import { ipcRenderer } from 'electron';
const path = window.require('path');

// 基础平台配置
const basePlatforms = [
    { label: '小红书', type: 'red', url: 'https://creator.xiaohongshu.com' },
    { label: '抖音', type: 'tiktok', url: 'https://creator.douyin.com' },
    { label: '快手', type: 'kuaishou', url: 'https://cp.kuaishou.com' },
    { label: '视频号', type: 'sph', url: 'https://channels.weixin.qq.com' },
];

// 异步初始化platforms
export async function getPlatforms() {
    try {
        const srcDir = await ipcRenderer.invoke('getpath');
        return basePlatforms.map(platform => ({
            ...platform,
            js: 'file://' + path.join(srcDir, platform.type + '.js')
        }));
    } catch (error) {
        console.error('获取平台配置失败:', error);
        return basePlatforms;
    }
}


export async function getScript(platform_type) {
    try {
        const srcDir = await ipcRenderer.invoke('getpath');
        return 'file://' + path.join(srcDir,platform_type + '.js')
    } catch (error) {
        console.error('获取平台配置失败:', error);
        return '';
    }
}

export async function getAiScript(platform_type) {
    try {
        const srcDir = await ipcRenderer.invoke('getaipath');
        return 'file://' + path.join(srcDir,platform_type + '.js')
    } catch (error) {
        console.error('获取平台配置失败:', error);
        return '';
    }
}

// 为了向后兼容，导出一个默认的空数组
export const platforms = [];