<template>
  <div class="push-page">

    <!-- 发布控制区域 -->
    <div class="control-section">
      <div class="section-title">
        <h3>发布控制</h3>

      </div>
      <div class="control-panel">
        <div class="control-buttons">
          <div 
            class="control-button primary" 
            :class="{ loading: publishing }"
            @click="handlePublish">
            <div class="button-icon">
              <i class="el-icon-video-play"></i>
            </div>
            <div class="button-text">{{ publishing ? '发布中...' : '开始发布' }}</div>
          </div>
          <div 
            class="control-button danger" 
            @click="handleStop">
            <div class="button-icon">
              <i class="el-icon-video-camera"></i>
            </div>
            <div class="button-text">停止发布</div>
          </div>
        </div>
        <div class="status-indicator">
          <!-- <div class="status-label">任务状态</div> -->
          <div class="status-display" :class="getStatusType()">
            <i :class="getStatusIcon()" class="status-icon"></i>
            <span class="status-text">{{ getStatusText() }}</span>
          </div>
        </div>
      </div>
    </div>

    <!-- 配置区域 -->
    <div class="config-section">
      <div class="section-title">
        <h3>发布配置</h3>
      </div>
      <div class="config-panel">
        <div class="config-form">
          <div class="config-row">
            <div class="config-item">
              <label class="config-label">自动打开浏览器</label>
              <div class="config-control">
                <el-switch 
                  v-model="config.autoOpenBrowser" 
                  active-text="关闭"
                  inactive-text="开启">
                </el-switch>
              </div>
            </div>
            <div class="config-item">
              <label class="config-label">作品发布间隔(秒)</label>
              <div class="config-control" style="width: 150px;">
                <el-input-number 
                  v-model="config.publishInterval" 
                  :min="1" 
                  size="medium" 
                  style="width: 100%;">
                </el-input-number>
              </div>
             <el-button type="primary" @click="saveConfig" style="margin-left: 50px;">保存配置</el-button>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 统计信息区域 -->
    <div class="stats-section">
      <div class="section-title">
        <h3>发布统计</h3>
        <div class="stats-controls">
          <el-button 
            size="small" 
            icon="el-icon-refresh" 
            @click="refreshStats"
            :loading="statsLoading">
            刷新
          </el-button>
        </div>
      </div>
      <div class="stats-grid">
        <div class="stat-card">
          <div class="stat-icon primary">
            <i class="el-icon-user"></i>
          </div>
          <div class="stat-content">
            <div class="stat-number">{{ stats.userCount }}</div>
            <div class="stat-label">授权账号数</div>
          </div>
        </div>
        <div class="stat-card">
          <div class="stat-icon success">
            <i class="el-icon-s-promotion"></i>
          </div>
          <div class="stat-content">
            <div class="stat-number">{{ stats.todaySendCount }}</div>
            <div class="stat-label">今日发布</div>
          </div>
        </div>
        <div class="stat-card">
          <div class="stat-icon warning">
            <i class="el-icon-s-marketing"></i>
          </div>
          <div class="stat-content">
            <div class="stat-number">{{ stats.allSendCount }}</div>
            <div class="stat-label">累计发布</div>
          </div>
        </div>
        <div class="stat-card">
          <div class="stat-icon danger">
            <i class="el-icon-document"></i>
          </div>
          <div class="stat-content">
            <div class="stat-number">{{ stats.articleCount }}</div>
            <div class="stat-label">文章数</div>
          </div>
        </div>
      </div>
    </div>

    <!-- 发布日志区域 -->
    <div class="log-section">
      <div class="section-title">
        <h3>发布日志</h3>
        <div class="log-controls">
          <el-button size="small" @click="clearLogs">清空日志</el-button>
          <el-button size="small" @click="exportLogs">导出日志</el-button>
          <!-- <el-button size="small" @click="testLogDisplay" type="success">测试日志</el-button> -->
          <div class="log-filters">
          <el-select v-model="logFilter" placeholder="筛选日志级别" size="small" style="width: 120px;">
            <el-option label="全部" value="all"></el-option>
            <el-option label="成功" value="success"></el-option>
            <el-option label="错误" value="error"></el-option>
            <el-option label="警告" value="warning"></el-option>
            <el-option label="信息" value="info"></el-option>
          </el-select>
        </div>
        </div>
      </div>
      <div class="log-panel">

        <div class="log-container" ref="logContainer">
          <div 
            v-for="(log, index) in filteredLogs" 
            :key="index"
            :class="['log-item', `log-${log.level}`]">
            <div class="log-time">{{ formatTime(log.timestamp) }}</div>
            <div class="log-level">
              <el-tag :type="getLogTagType(log.level)" size="mini">
                {{ log.level.toUpperCase() }}
              </el-tag>
            </div>
            <div class="log-message">{{ log.message }}</div>
          </div>
          <div v-if="filteredLogs.length === 0" class="no-logs">
            暂无日志
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import {getPushLogs, getPushStats, startPushTask, stopFlaskPush, getFlaskLogs, getTongji} from '@/api/push'

export default {
  name: 'Push',
  data() {
    return {
      publishing: false,
      config: {
        autoOpenBrowser: true,
        publishInterval: 10,
        maxRetries: 3,
        statsPollingInterval: 30, // 统计轮询间隔（秒）
        googlePath: '' // 谷歌浏览器路径
      },
      task_id: null, // 任务ID
      logs: [],
      logFilter: 'all',
      stats: {
        userCount: 0,
        todaySendCount: 0,
        allSendCount: 0,
        articleCount: 0
      },
      logPollingTimer: null,
      statsPollingTimer: null,
      statsLoading: false, // 统计加载状态
      udid:'',
      uid:'',
      runStatus: 'idle', // idle | running | stopped
      last_version: -1,
    }
  },
  computed: {
    filteredLogs() {
      if (this.logFilter === 'all') {
        return this.logs
      }
      return this.logs.filter(log => log.level === this.logFilter)
    }
  },
  mounted() {
    const userInfoStr = localStorage.getItem('userInfo'); // 获取字符串
    const userInfo = JSON.parse(userInfoStr); // 解析为对象

    this.udid = userInfo.udid; // 正确访问属性
    this.uid = userInfo.uid;

    this.loadConfig()
    this.fetchTongji()
    this.startStatsPolling() // 启动统计轮询
    this.addInitialLogs()
  },
  activated() {
    // 组件被激活时，如果有任务在运行，重新启动轮询
    if (this.runStatus === 'running' && this.task_id) {
      this.startLogPolling(this.task_id)
    }
    this.startStatsPolling() // 重新启动统计轮询
  },
  deactivated() {
    // 组件被缓存时，停止轮询
    this.stopPolling()
    this.stopLogPolling()
    this.stopStatsPolling()
  },
  beforeDestroy() {
    this.stopPolling()
    this.stopLogPolling()
    this.stopStatsPolling()
  },
  methods: {
    async fetchTongji() {
      try {
        // 调用新的统计接口
        const res = await getTongji({
          udid: this.udid,
          uid: this.uid
        });
        
        if (res && res.code === 1 && res.data) {
          const d = res.data
          this.stats = {
            userCount: Number(d.user_count) || 0,
            todaySendCount: Number(d.today_send_count) || 0,
            allSendCount: Number(d.all_send_count) || 0,
            articleCount: Number(d.article_count) || 0
          }
        }
      } catch (error) {
        console.error('获取统计失败:', error)
      }
    },

    async refreshStats() {
      this.statsLoading = true
      try {
        await this.fetchTongji()
        this.$message.success('统计数据已更新')
      } catch (error) {
        this.$message.error('更新统计数据失败')
      } finally {
        this.statsLoading = false
      }
    },
    async handlePublish() {
      try {
        this.loadConfig()
        this.publishing = true
        const systemConfig = localStorage.getItem('systemConfig')
        const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
        const agent_ip_username = systemConfig ? JSON.parse(systemConfig).agent_ip_username || '' : ''
        // 准备请求数据
        const data = {
          uid: this.uid,
          udid: this.udid,
          my_headless: this.config.autoOpenBrowser,
          publish_interval: this.config.publishInterval,
          google_path: this.config.googlePath,
          api_url: localStorage.getItem('api_url') || '',
          agent_ip_url: agent_ip_url,
          agent_ip_username: agent_ip_username,
        }

        
        // 调用统一的发布任务启动接口
        const response = await startPushTask(data);
        
        if (response.code == 1) {
          this.task_id = response.task_id
          this.$message.success('发布已开始')
          this.addLog('info', '发布任务已启动')
          this.publishing = false
          this.runStatus = 'running'
          // 开始轮询日志
          this.startLogPolling(response.task_id)
        } else {
          this.$message.warning('启动发布失败: ' + response.msg)
          this.addLog('warning', '启动发布失败: ' + response.msg)
          this.publishing = false
          this.runStatus = 'stopped'
        }
      } catch (error) {
        this.$message.error('启动发布失败: ' + error.message)
        this.addLog('error', '启动发布失败: ' + error.message)
        this.publishing = false
        this.runStatus = 'stopped'
      }
    },
    async handleStop() {
      try {
        // 调用Flask停止接口
        await stopFlaskPush();
        this.publishing = false
        this.runStatus = 'stopped'
        this.$message.info('发布已停止')
        this.addLog('info', '发布任务已停止')
        
        // 停止日志轮询
        this.stopLogPolling()
      } catch (error) {
        this.$message.error('停止发布失败: ' + error.message)
        this.addLog('error', '停止发布失败: ' + error.message)
      }
    },
    async saveConfig() {
      try {
        // 模拟保存配置
        localStorage.setItem('pushConfig', JSON.stringify(this.config))
        this.$message.success('配置已保存')
        this.addLog('info', '发布配置已更新')
      } catch (error) {
        this.$message.error('保存配置失败: ' + error.message)
        this.addLog('error', '保存配置失败: ' + error.message)
      }
    },

    async loadConfig() {
      try {
        // 加载Push配置
        const savedConfig = localStorage.getItem('pushConfig')
        if (savedConfig) {
          this.config = { ...this.config, ...JSON.parse(savedConfig) }
        }
        
        // 从系统配置中加载谷歌浏览器路径
        const systemConfig = localStorage.getItem('systemConfig')
        if (systemConfig) {
          const parsedSystemConfig = JSON.parse(systemConfig)
          if (parsedSystemConfig.googlePath) {
            this.config.googlePath = parsedSystemConfig.googlePath
          }
        }
      } catch (error) {
        console.error('加载配置失败:', error)
      }
    },
    startStatsPolling() {
      // 启动统计轮询，使用配置中的间隔时间
      const interval = (this.config.statsPollingInterval || 30) * 1000 // 转换为毫秒
      this.statsPollingTimer = setInterval(() => {
        this.fetchTongji()
      }, interval)
    },
    
    startLogPolling(taskId) {
      // 开始轮询 Flask 服务器日志
      console.log('开始轮询日志，任务ID:', taskId); // 添加调试日志
      this.logPollingTimer = setInterval(async () => {
        try {
          const response = await getFlaskLogs(taskId,this.last_version);
          console.log('轮询日志响应:', response); // 添加调试日志
          
          if (response.code === 1) {
            // 更新日志 - Flask 返回的整个响应就是日志数据
            this.updateLogsFromFlask(response);
          } else {
            console.log('日志响应状态异常:', response); // 添加调试日志
          }
        } catch (error) {
          console.error('获取日志失败:', error);
        }
      }, 1000);
    },
    
    updateLogsFromFlask(flaskLogs) {
      // 将 Flask 服务器的日志转换为本地日志格式
      console.log('收到 Flask 日志:', flaskLogs);

      if (!flaskLogs || typeof flaskLogs !== 'object') {
        console.log('无效的日志数据:', flaskLogs);
        return;
      }

      const msg = typeof flaskLogs.msg === 'string' ? flaskLogs.msg : '';
      this.last_version = flaskLogs.msg_version;
      const msgVersion = flaskLogs.msg_version;
      const serverStatus = flaskLogs.status;


      // 更新运行状态（如果后端提供）
      if (typeof serverStatus === 'string') {
        const normalized = serverStatus.toLowerCase();
        if (normalized === 'running') this.runStatus = 'running';
        if (normalized === 'stopped' || normalized === 'finished' || normalized === 'idle') this.runStatus = 'stopped';
      }

      // msg 为空则不添加
      if (!msg || msg.trim() === '') {
        console.log('空消息，跳过添加');
        return;
      }

      // msg 和 msg_version 相同则认为是同一条日志，不添加
      // const isDuplicate = this.logs.some(l => l.message === msg && l.msg_version === this.last_version);
      // if (isDuplicate) {
      //   // console.log('重复日志，跳过添加');
      //   return;
      // }

      const newLog = {
        timestamp: flaskLogs.timestamp ? new Date(flaskLogs.timestamp * 1000) : new Date(),
        level: flaskLogs.level || 'info',
        message: msg,
        msg_version: msgVersion
      };

      console.log('添加新日志:', newLog);
      this.logs.push(newLog);
      
      // 当日志超过200条时，清除最前面的日志
      if (this.logs.length > 200) {
        this.logs.splice(0, this.logs.length - 200);
      }
      
      this.scrollToBottom();
    },
    stopPolling() {
      if (this.logPollingTimer) {
        clearInterval(this.logPollingTimer)
        this.logPollingTimer = null
      }
      if (this.statsPollingTimer) {
        clearInterval(this.statsPollingTimer)
        this.statsPollingTimer = null
      }
    },
    
    stopLogPolling() {
      if (this.logPollingTimer) {
        clearInterval(this.logPollingTimer)
        this.logPollingTimer = null
      }
    },

    stopStatsPolling() {
      if (this.statsPollingTimer) {
        clearInterval(this.statsPollingTimer)
        this.statsPollingTimer = null
      }
    },

    addInitialLogs() {
      this.addLog('info', '发布系统已就绪')
      this.addLog('info', '等待开始发布任务...')
    },


    async fetchLogs() {
      try {
        const response = await getPushLogs()
        this.logs = response.data || []
        this.scrollToBottom()
      } catch (error) {
        console.error('获取日志失败:', error)
      }
    },
    async fetchStats() {
      try {
        const response = await getPushStats()
        this.stats = response.data || this.stats
      } catch (error) {
        console.error('获取统计失败:', error)
      }
    },
    addLog(level, message) {
      this.logs.push({
        timestamp: new Date(),
        level,
        message
      })
      
      // 当日志超过200条时，清除最前面的日志
      if (this.logs.length > 200) {
        this.logs.splice(0, this.logs.length - 200);
      }
      
      this.scrollToBottom()
    },
    scrollToBottom() {
      this.$nextTick(() => {
        const container = this.$refs.logContainer
        if (container) {
          container.scrollTop = container.scrollHeight
        }
      })
    },
    clearLogs() {
      this.logs = []
      this.$message.success('日志已清空')
    },
    exportLogs() {
      const logText = this.logs.map(log => 
        `[${this.formatTime(log.timestamp)}] [${log.level.toUpperCase()}] ${log.message}`
      ).join('\n')
      
      const blob = new Blob([logText], { type: 'text/plain' })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `push-logs-${new Date().toISOString().slice(0, 10)}.txt`
      a.click()
      URL.revokeObjectURL(url)
      
      this.$message.success('日志已导出')
    },
    
    testLogDisplay() {
      // 测试日志显示功能
      const testLog = {
        timestamp: new Date(),
        level: 'info',
        message: '这是一条测试日志 - ' + new Date().toLocaleTimeString()
      };
      
      this.logs.push(testLog);
      this.scrollToBottom();
      this.$message.success('测试日志已添加');
      
      // 模拟 Flask 日志格式
      const flaskTestLog = {
        code: 1,
        level: 'info',
        msg: '模拟 Flask 日志 - ' + new Date().toLocaleTimeString(),
        msg_version: 1,
        status: 'running',
        timestamp: Math.floor(Date.now() / 1000)
      };
      
      this.updateLogsFromFlask(flaskTestLog);
      this.$message.success('Flask 测试日志已添加');
    },
    getStatusType() {
      if (this.runStatus === 'running') return 'success'
      if (this.runStatus === 'stopped') return 'info'
      return 'warning'
    },
    getStatusText() {
      if (this.runStatus === 'running') return '任务正在进行中'
      if (this.runStatus === 'stopped') return '无正在进行中的任务'
      return '无正在进行中的任务'
    },
    getStatusIcon() {
      if (this.runStatus === 'running') return 'el-icon-success'
      if (this.runStatus === 'stopped') return 'el-icon-circle-close'
      return 'el-icon-time'
    },
    getLogTagType(level) {
      const typeMap = {
        success: 'success',
        error: 'danger',
        warning: 'warning',
        info: 'info'
      }
      return typeMap[level] || 'info'
    },
    formatTime(timestamp) {
      const date = new Date(timestamp)
      return date.toLocaleTimeString()
    },
    getProgressPercentage() {
      const total = this.stats.totalPublished + this.stats.pendingCount
      if (total === 0) return 0
      return Math.round((this.stats.totalPublished / total) * 100)
    }
  }
}
</script>

<style lang="scss" scoped>
.push-page {
  padding: 20px;
  background: var(--bg-primary);
  min-height: calc(100vh - 120px);

  .section-title {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
    
    h3 {
      margin: 0;
      color: var(--text-primary);
      font-size: 18px;
      font-weight: 600;
    }
    
    .current-time {
      font-size: 14px;
      color: var(--text-secondary);
      font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
    }
  }

  .control-section {
    background: var(--bg-secondary);
    border-radius: var(--radius-lg);
    padding: 24px;
    margin-bottom: 24px;
    box-shadow: var(--shadow-md);
    border: 1px solid var(--border-color);

    .control-panel {
        display: flex;
        justify-content: space-between;
        align-items: center;
        flex-wrap: wrap;
        gap: 20px;
        min-height: 80px;

        .control-buttons {
          display: flex;
          gap: 16px;
          flex-wrap: wrap;
          align-items: center;
        }

      .control-button {
        display: flex;
        align-items: center;
        gap: 8px;
        padding: 12px 16px;
        border-radius: var(--radius-lg);
        cursor: pointer;
        transition: all var(--transition-normal);
        position: relative;
        overflow: hidden;
        
        &::before {
          content: '';
          position: absolute;
          top: 0;
          left: -100%;
          width: 100%;
          height: 100%;
          background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
          transition: left var(--transition-slow);
        }
        
        &:hover {
          transform: translateY(-2px);
          box-shadow: var(--shadow-lg);
          
          &::before {
            left: 100%;
          }
        }
        
        &.primary {
          background: linear-gradient(135deg, #007AFF 0%, #00B0FF 100%);
          color: white;
        }
        
        &.danger {
          background: linear-gradient(135deg, #FF5252 0%, #FF8A80 100%);
          color: white;
        }
        
        &.loading {
          opacity: 0.8;
          cursor: not-allowed;
        }

        .button-icon {
          width: 24px;
          height: 24px;
          border-radius: 50%;
          background: rgba(255, 255, 255, 0.2);
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 14px;
        }

        .button-text {
          font-size: 14px;
          font-weight: 600;
        }
      }

      .status-indicator {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        gap: 8px;
        min-width: 200px;
        height: 100%;
        padding: 0 20px;

        .status-label {
          font-size: 12px;
          color: var(--text-secondary);
          letter-spacing: 1px;
          margin-bottom: 4px;
        }

        .status-display {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          font-size: 14px;
          line-height: 1;
          min-width: 120px;
          text-align: center;
          transition: all 0.3s ease;
          padding: 8px 0;
          position: relative;
          overflow: hidden;
          
          &.success {
            color: #00C853;
            animation: statusPulse 2s infinite;
          }
          
          &.info {
            color: #64B5F6;
          }
          
          &.warning {
            color: #FF9800;
          }
        }
        
        .status-icon {
          font-size: 18px;
          
          .status-display.success & {
            animation: spin 2s linear infinite;
          }
          
          .status-display.info & {
            animation: pulse 1.5s infinite;
          }
          
          .status-display.warning & {
            animation: bounce 1s infinite;
          }
        }
        
        .status-text {
          font-weight: 500;
          transition: all 0.3s ease;
          
          .status-display.success & {
            animation: textGlow 2s infinite;
          }
        }
        
        @keyframes spin {
          from {
            transform: rotate(0deg);
          }
          to {
