<template>
  <div class="ai-tools">
    <!-- 发布控制区域 -->
    <div class="control-section">
      <div class="section-title">
        <h3>查询控制</h3>
      </div>
      <div class="control-panel">
        <div class="control-buttons">
          <div 
            class="control-button primary" 
            :class="{ loading: isExecuting }"
            @click="startExecution">
            <div class="button-icon">
              <i class="el-icon-caret-right"></i>
            </div>
            <div class="button-text">{{ isExecuting ? '执行中...' : '开始查询' }}</div>
          </div>
          <div 
            class="control-button danger" 
            @click="stopExecution">
            <div class="button-icon">
              <i class="el-icon-close"></i>
            </div>
            <div class="button-text">停止执行</div>
          </div>
        </div>
        <div class="status-indicator">
          <!-- <div class="status-label">任务状态</div> -->
          <div class="status-display" :class="getStatusType()">
            <i :class="getStatusIcon()" class="status-icon"></i>
            <span class="status-text">{{ getStatusText() }}</span>
          </div>
        </div>
      </div>
    </div>

    <!-- 配置区域 -->
    <div class="config-section">
      <div class="section-title">
        <h3>查询配置</h3>
      </div>
      <div class="config-panel">
        <div class="config-form">
          <div class="config-row">
            <div class="config-item">
              <label class="config-label">自动打开浏览器</label>
              <div class="config-control">
                <el-switch 
                  v-model="config.autoOpenBrowser" 
                  active-text="关闭"
                  inactive-text="开启">
                </el-switch>
              </div>
            </div>
            <div class="config-item">
              <label class="config-label">任务时间间隔(秒)</label>
              <div class="config-control" style="width: 150px;">
                <el-input-number 
                  v-model="config.publishInterval" 
                  :min="1" 
                  size="medium" 
                  style="width: 100%;">
                </el-input-number>
              </div>
              <el-button type="primary" @click="saveConfig" style="margin-left: 50px;">保存配置</el-button>
            </div>
 
          </div>
        </div>
      </div>
    </div>

    <!-- AI 分类选择 -->
    <div class="ai-section">
      <div class="section-title">
        <h3>AI 分类</h3>
      </div>
      <div class="ai-top-grid">
        <div
          class="ai-card"
          v-for="m in models"
          :key="m.value"
          :class="{ 
            'ai-card-disabled': !m.status,
            'ai-card-selected': selectedModel === m.value
          }"
          @click="selectModel(m)"
        >
          <div class="ai-card-inner">
            <img v-if="m.icon" class="ai-icon" :src="m.icon" alt="icon" />
            <span class="ai-name">{{ m.label }}</span>
            <span v-if="!m.status" class="status-disabled">(暂未开放)</span>
            <i v-if="selectedModel === m.value" class="el-icon-check selected-icon"></i>
          </div>
        </div>
      </div>
    </div>

    <!-- 执行日志区域 -->
    <div class="log-section">
      <div class="section-title">
        <h3>执行日志</h3>
        <div class="log-controls">
          <el-select v-model="logFilter" placeholder="筛选日志级别" size="small" style="width: 120px;">
            <el-option label="全部" value="all"></el-option>
            <el-option label="成功" value="success"></el-option>
            <el-option label="错误" value="error"></el-option>
            <el-option label="警告" value="warning"></el-option>
            <el-option label="信息" value="info"></el-option>
          </el-select>
          <el-button size="small" @click="clearLogs">清空</el-button>
          <el-button size="small" @click="exportLogs">导出</el-button>
        </div>
      </div>
      <div class="log-panel">
        <div class="log-container" ref="logContainer">
          <div 
            v-for="(log, index) in filteredLogs" 
            :key="index"
            :class="['log-item', `log-${log.level}`]">
            <div class="log-time">{{ formatTime(log.timestamp) }}</div>
            <div class="log-level">
              <el-tag :type="getLogTagType(log.level)" size="mini">
                {{ (log.level || 'info').toUpperCase() }}
              </el-tag>
            </div>
            <div class="log-message">{{ log.message }}</div>
          </div>
          <div v-if="filteredLogs.length === 0" class="no-logs">暂无日志</div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { getModelList } from '@/api/index.js'
import { startAiPushTask, stopAiFlaskPush, getAiFlaskLogs } from '@/api/push.js'

export default {
  name: 'AiTools',
  data() {
    return {
      udid:'',
      uid:'',
      models: [],
      selectedModel: null,
      modelIdMap: { 
        'deepseek': 1, 
        'doubao': 2, 
        'yuanbao': 3, 
        'qianwen': 4, 
        'wenxin': 5, 
        'nami': 6, 
        'kimi': 7, 
        'zhipu': 8 
      },
      config: {
        execMode: 'sequential',
        autoOpenBrowser: true,
        publishInterval: 10,
        googlePath: ''
      },
      keywordsText: '',
      hitWordsText: '',
      logs: [],
      isExecuting: false,
      runStatus: 'idle',
      logFilter: 'all',
      task_id: null,
      logPollingInterval: null,
      lastLogVersion: 0
    }
  },
  created() {
    const userInfoStr = localStorage.getItem('userInfo'); // 获取字符串
    const userInfo = JSON.parse(userInfoStr); // 解析为对象

    this.udid = userInfo.udid; // 正确访问属性
    this.uid = userInfo.uid;
    console.log("UDID:", this.udid); // 正常输出 "1434
    this.loadConfig()
    this.loadModels()
    this.refreshMock()
    this.updateCurrentTime()
    this.startTimeUpdate()
  },
  activated() {
    // 组件被激活时，如果有任务在运行，重新启动轮询
    if (this.runStatus === 'running' && this.task_id) {
      this.startLogPolling(this.task_id)
    }
  },
  deactivated() {
    // 组件被缓存时，停止轮询
    if (this.logPollingInterval) {
      clearInterval(this.logPollingInterval)
      this.logPollingInterval = null
    }
  },
  computed: {
    filteredLogs() {
      if (this.logFilter === 'all') {
        return this.logs
      }
      return (this.logs || []).filter(l => (l.level || 'info') === this.logFilter)
    }
  },
  methods: {
    selectModel(model) {
      if (!model.status) return; // 如果模型未开放，不允许选择
      
      // 如果点击已选中的模型，则取消选择
      if (this.selectedModel === model.value) {
        this.selectedModel = null;
        return;
      }
      
      this.selectedModel = model.value;
    },
    
    async loadModels() {
      try {
        const response = await getModelList({ udid: this.udid, uid: this.uid })
        if (response && response.code === 1 && response.data) {
          this.models = response.data.map(item => ({
            label: item.name,
            value: item.platform_type,
            icon: item.avatar,
            status: item.status
          }))
          console.log('模型列表加载成功:', this.models)
          // 默认不选择模型
          this.selectedModel = null;
        }
      } catch (error) {
        console.error('加载模型列表失败:', error)
        this.$message.error('加载模型列表失败')
      }
    },

    refreshMock() {
      this.logs = []
      // this.addLog('info', '初始化配置完成')
      // this.addLog('info', '开始拉取关键词...')
   
    },
    
    // 启动执行
    async startExecution() {
      try {
        this.loadConfig()
        this.isExecuting = true
        this.runStatus = 'running'
        this.logs = []
        
        // 获取映射后的model_type值
        let mappedModelType = '';
        if (this.selectedModel) {
          mappedModelType = this.modelIdMap[this.selectedModel] || '';
        }
        const systemConfig = localStorage.getItem('systemConfig')
        const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
        const agent_ip_username = systemConfig ? JSON.parse(systemConfig).agent_ip_username || '' : ''
        // 添加启动日志
        // 准备请求数据，包含配置参数
        const data = {
          uid: this.uid,
          udid: this.udid,
          model_type: mappedModelType, // 传递映射后的model_type，不选择则为空
          my_headless: this.config.autoOpenBrowser,
          publish_interval: this.config.publishInterval,
          google_path: this.config.googlePath,
          api_url: localStorage.getItem('api_url'),
          agent_ip_url: agent_ip_url,
          agent_ip_username: agent_ip_username,
        }
        
        // 添加配置信息日志
        // this.addLog('info', `配置信息: 浏览器=${this.config.autoOpenBrowser}?打开:关闭, 发布间隔=${this.config.publishInterval}秒`)
        
        // 调用AI发布任务启动接口
        const response = await startAiPushTask(data);
        
        if (response.code == 1) {
          this.task_id = response.task_id
          this.$message.success('任务已开始')
          this.addLog('info', '查收任务已启动')
          // 开始轮询日志
          this.startLogPolling(response.task_id)
        } else {
          this.$message.warning('启动任务失败: ' + response.msg)
          this.addLog('warning', '启动任务失败: ' + response.msg)
          this.isExecuting = false
          this.runStatus = 'stopped'
        }
      } catch (error) {
        this.$message.error('启动任务失败: ' + error.message)
        this.addLog('error', '启动任务失败: ' + error.message)
        this.isExecuting = false
        this.runStatus = 'stopped'
      }
    },
    
    // 停止执行
    async stopExecution() {
      try {
        // 调用停止AI任务接口
        await stopAiFlaskPush();
        this.isExecuting = false
        this.runStatus = 'stopped'
        this.addLog('warning', '任务已停止')
        this.$message.info('任务已停止')
        
        // 停止日志轮询
        if (this.logPollingInterval) {
          clearInterval(this.logPollingInterval)
          this.logPollingInterval = null
        }
      } catch (error) {
        this.$message.error('停止任务失败: ' + error.message)
        this.addLog('error', '停止任务失败: ' + error.message)
      }
    },
    
    // 添加日志
    addLog(level, message) {
      this.logs.push({ timestamp: new Date(), level, message })
      this.scrollToBottom()
    },
    
    // 开始日志轮询
    startLogPolling(taskId) {
      // 清除之前的轮询
      if (this.logPollingInterval) {
        clearInterval(this.logPollingInterval)
      }
      
      this.lastLogVersion = 0
      
      // 设置轮询间隔
      this.logPollingInterval = setInterval(async () => {
        try {
          const response = await getAiFlaskLogs(taskId, this.lastLogVersion)
          
          if (response && response.code === 1) {
            // 更新最新的日志版本
            this.lastLogVersion = response.msg_version || 0
            
            // 添加新日志
            if (response.msg && response.msg.trim()) {
              this.addLog(response.level || 'info', response.msg)
            }
          }
        } catch (error) {
          console.error('获取日志失败:', error)
        }
      }, 1000) // 每秒轮询一次
    },
    clearLogs() {
      this.logs = []
      this.$message.success('日志已清空')
    },
    exportLogs() {
      const logText = this.logs.map(log => `[${this.formatTime(log.timestamp)}] [${(log.level||'info').toUpperCase()}] ${log.message}`).join('\n')
      const blob = new Blob([logText], { type: 'text/plain' })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `ai-tools-logs-${new Date().toISOString().slice(0,10)}.txt`
      a.click()
      URL.revokeObjectURL(url)
      this.$message.success('日志已导出')
    },
    scrollToBottom() {
      this.$nextTick(() => {
        const container = this.$refs.logContainer
        if (container) {
          container.scrollTop = container.scrollHeight
        }
      })
    },
    getLogTagType(level) {
      const typeMap = { success: 'success', error: 'danger', warning: 'warning', info: 'info' }
      return typeMap[level] || 'info'
    },
    formatTime(timestamp) {
      const date = new Date(timestamp)
      return date.toLocaleTimeString()
    },
    getStatusType() {
      if (this.runStatus === 'running') return 'success'
      if (this.runStatus === 'stopped') return 'info'
      return 'warning'
    },
    getStatusText() {
      if (this.runStatus === 'running') return '任务执行中'
      if (this.runStatus === 'stopped') return '任务已停止'
      return '没有执行的任务'
    },
    getStatusIcon() {
      if (this.runStatus === 'running') return 'el-icon-success'
      if (this.runStatus === 'stopped') return 'el-icon-circle-close'
      return 'el-icon-time'
    },
    
    // 保存配置
    async saveConfig() {
      try {
        localStorage.setItem('aiToolsConfig', JSON.stringify(this.config))
        this.$message.success('配置已保存')
        this.addLog('info', 'AI发布配置已更新')
      } catch (error) {
        this.$message.error('保存配置失败: ' + error.message)
        this.addLog('error', '保存配置失败: ' + error.message)
      }
    },

    // 加载配置
    loadConfig() {
      try {
        // 加载AI工具配置
        const savedConfig = localStorage.getItem('aiToolsConfig')
        if (savedConfig) {
          this.config = { ...this.config, ...JSON.parse(savedConfig) }
        }
        
        // 从系统配置中加载谷歌浏览器路径
        const systemConfig = localStorage.getItem('systemConfig')
        if (systemConfig) {
          const parsedSystemConfig = JSON.parse(systemConfig)
          if (parsedSystemConfig.googlePath) {
            this.config.googlePath = parsedSystemConfig.googlePath
          }
        }
      } catch (error) {
        console.error('加载配置失败:', error)
      }
    },
  }
}
</script>

<style scoped lang="scss">
.ai-tools {
  padding: 20px;
  background: var(--bg-primary);
  min-height: calc(100vh - 120px);
  display: flex;
  flex-direction: column;
}

.section-title {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  
  h3 {
    margin: 0;
    color: var(--text-primary);
    font-size: 18px;
    font-weight: 600;
  }
  
  .current-time {
    font-size: 14px;
    color: var(--text-secondary);
    font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
  }
}

/* 发布控制区域 */
.control-section {
  background: var(--bg-secondary);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 24px;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--border-color);

  .control-panel {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 20px;

    .control-buttons {
      display: flex;
      gap: 16px;
      flex-wrap: wrap;
    }

    .control-button {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 12px 16px;
      border-radius: var(--radius-lg);
      cursor: pointer;
      transition: all var(--transition-normal);
      position: relative;
      overflow: hidden;
      
      &::before {
        content: '';
        position: absolute;
        top: 0;
        left: -100%;
        width: 100%;
        height: 100%;
        background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
        transition: left var(--transition-slow);
      }
      
      &:hover {
        transform: translateY(-2px);
        box-shadow: var(--shadow-lg);
        
        &::before {
          left: 100%;
        }
      }
      
      &.primary {
        background: linear-gradient(135deg, #007AFF 0%, #00B0FF 100%);
        color: white;
      }
      
      &.danger {
        background: linear-gradient(135deg, #FF5252 0%, #FF8A80 100%);
        color: white;
      }
      
      &.loading {
        opacity: 0.8;
        cursor: not-allowed;
      }

      .button-icon {
        width: 24px;
        height: 24px;
        border-radius: 50%;
        background: rgba(255, 255, 255, 0.2);
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 14px;
      }

      .button-text {
        font-size: 14px;
        font-weight: 600;
      }
    }

    .status-indicator {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        gap: 8px;
        min-width: 200px;
        height: 100%;
        padding: 0 20px;

        .status-label {
          font-size: 12px;
          color: var(--text-secondary);
          letter-spacing: 1px;
          margin-bottom: 4px;
        }

        .status-display {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          font-size: 14px;
          line-height: 1;
          min-width: 120px;
          text-align: center;
          transition: all 0.3s ease;
          padding: 8px 0;
          position: relative;
          overflow: hidden;
          
          &.success {
            color: #00C853;
            animation: statusPulse 2s infinite;
          }
          
          &.info {
            color: #64B5F6;
          }
          
          &.warning {
            color: #FF9800;
          }
        }
        
        .status-icon {
          font-size: 18px;
          
          .status-display.success & {
            animation: spin 2s linear infinite;
          }
          
          .status-display.info & {
            animation: pulse 1.5s infinite;
          }
          
          .status-display.warning & {
            animation: bounce 1s infinite;
          }
        }
        
        .status-text {
          font-weight: 500;
          transition: all 0.3s ease;
          
          .status-display.success & {
            animation: textGlow 2s infinite;
          }
        }
        
        @keyframes spin {
          from {
            transform: rotate(0deg);
          }
          to {
            transform: rotate(360deg);
          }
        }
        
        @keyframes statusPulse {
          0% {
            opacity: 1;
            transform: scale(1);
          }
          50% {
            opacity: 0.8;
            transform: scale(1.05);
          }
          100% {
            opacity: 1;
            transform: scale(1);
          }
        }
        
        @keyframes pulse {
          0% {
            transform: scale(1);
          }
          50% {
            transform: scale(1.2);
          }
          100% {
            transform: scale(1);
          }
        }
        
        @keyframes bounce {
          0%, 20%, 50%, 80%, 100% {
            transform: translateY(0);
          }
          40% {
            transform: translateY(-5px);
          }
          60% {
            transform: translateY(-3px);
          }
        }
        
        @keyframes textGlow {
          0% {
            text-shadow: 0 0 0px rgba(0, 200, 83, 0);
          }
          50% {
            text-shadow: 0 0 8px rgba(0, 200, 83, 0.6);
          }
          100% {
            text-shadow: 0 0 0px rgba(0, 200, 83, 0);
          }
        }
      }
  }
}

/* 配置区域 */
.config-section {
  background: var(--bg-secondary);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 24px;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--border-color);

  .config-panel {
    .config-form {
      max-width: 100%;
      
      .config-row {
        display: flex;
        align-items: center;
        flex-wrap: wrap;
        gap: 40px;
      }
      
      .config-item {
        display: flex;
        align-items: center;
        gap: 12px;
        min-width: 200px;
      }
      
      .config-label {
        width: 140px;
        font-weight: 500;
        color: var(--text-primary);
      }
      
      .config-control {
        flex: 1;
      }
      
      .config-button {
        margin-left: auto;
      }
    }
  }
}

/* AI 分类选择 */
.ai-section {
  background: var(--bg-secondary);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 24px;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--border-color);
}

.ai-top-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 12px;
}

.ai-card {
  border: 1px solid var(--border-color);
  border-radius: 10px;
  padding: 12px;
  cursor: pointer;
  background: var(--bg-tertiary);
  transition: background .2s, transform .1s;
  position: relative;
  
  &:hover {
    background: rgba(59, 130, 246, 0.1);
    transform: translateY(-1px);
  }
  
  &.ai-card-selected {
    border: 2px solid #3b82f6;
    background-color: rgba(59, 130, 246, 0.1);
  }
  
  &.ai-card-disabled {
    opacity: 0.6;
    cursor: not-allowed;
    
    &:hover {
      background: var(--bg-tertiary);
      transform: none;
    }
  }
}

.ai-card-inner {
  display: flex;
  align-items: center;
  gap: 8px;
}

.ai-icon {
  width: 20px;
  height: 20px;
  border-radius: 4px;
  object-fit: cover;
}

.ai-name {
  font-weight: 600;
  color: var(--text-primary);
}

.status-disabled {
  color: #f56c6c;
  font-size: 12px;
}

.selected-icon {
  position: absolute;
  top: 8px;
  right: 8px;
  color: #3b82f6;
  font-size: 16px;
}

/* 执行日志区域 */
.log-section {
  background: var(--bg-secondary);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 24px;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--border-color);

  .log-controls {
    display: flex;
    gap: 8px;
  }

  .log-panel {
    .log-container {
      height: 400px;
      overflow-y: auto;
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      padding: 12px;
      background: var(--bg-tertiary);

      .log-item {
        display: flex;
        align-items: center;
        padding: 8px 0;
        border-bottom: 1px solid var(--border-color);
        font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
        font-size: 13px;

        &:last-child {
          border-bottom: none;
