import axios from "axios";
import { Message } from 'element-ui';
import { getToken, removeToken } from './auth.js';
import router from '../router'

const service = axios.create({
    withCredentials: true, // 允许携带跨域凭证
    baseURL: 'http://8.138.58.181', // 接口基础地址
    timeout: 2000, // 超时时间（注意：原代码中的 `settimeout` 是错误的，应为 `timeout`）
});

// 添加请求拦截器
service.interceptors.request.use(
    config => {
        // 在发送请求之前做些什么
        config.headers['Authorization'] = 'Bearer ' + getToken(); // 添加 token 到请求头
        return config;
    },
    error => {
        // 对请求错误做些什么
        return Promise.reject(error);
    }
);

// 添加响应拦截器
service.interceptors.response.use(
    response => {
        // 对响应数据做点什么
        const res = response.data;
        console.log("resres",res)
        if (res.code && res.code !== 1) {
            console.log("code",res)
            Message({
                message: res.msg,
                type: 'error',
                duration: 2 * 1000
            });
            return Promise.reject(res.msg);
        } else {
            return res;
        }
    },
    error => {
        // 对响应错误做点什么
        if (error.response) {
            switch (error.response.status) {
                case 401:
                    // 清除 token
                    removeToken();
                    // 提示用户
                    Message({
                        message: '登录已过期，请重新登录',
                        type: 'error',
                        duration: 2 * 1000
                    });
                    // 跳转到登录页面
                    router.push({ path: '/login' });
                    break;
                default:
                    // 其他错误处理
                    // Message({
                    //     message: '异常错误，请联系管理员',
                    //     type: 'error',
                    //     duration: 2 * 1000
                    // });
                    break;
            }
        } else {
            // 网络错误或其他未知错误
            Message({
                message: '网络错误，请检查网络连接',
                type: 'error',
                duration: 2 * 1000
            });
        }
        return Promise.reject(error);
    }
);

export default service;