<template>
  <div class="ai-auth-webview">
    <div class="webview-header">
      <div class="webview-title">
        <span>{{ modelName }}</span>
      </div>
      
      <!-- 添加导航按钮组 -->
      <div class="webview-nav-buttons">
        <el-button 
          class="nav-btn" 
          type="primary" 
          size="small"
          :disabled="!canGoBack"
          @click="goBack">
          <i class="el-icon-arrow-left"></i>
          后退
        </el-button>
        
        <el-button 
          class="nav-btn" 
          type="primary" 
          size="small"
          :disabled="!canGoForward"
          @click="goForward">
          <i class="el-icon-arrow-right"></i>
          前进
        </el-button>
        
        <el-button 
          class="nav-btn" 
          type="success" 
          size="small"
          @click="refresh">
          <i class="el-icon-refresh"></i>
          刷新
        </el-button>
      </div>
      
      <el-button 
        class="webview-close-btn" 
        type="danger" 
        size="small"
        @click="closeWebview">
        <i class="el-icon-close"></i>
        关闭
      </el-button>
    </div>
    
    <!-- 添加加载状态显示 -->
    <div v-if="isLoading" class="loading-container">
      <div class="loading-content">
        <i class="el-icon-loading"></i>
        <p>正在准备登录状态...</p>
      </div>
    </div>
    
    <webview 
      v-if="webviewUrl && !isLoading" 
      :src="webviewUrl"
      class="webview-container"
      allowpopups
      :webpreferences="webPreferences">
    </webview>
  </div>
</template>

<script>
const { session } = require('@electron/remote')
import { getModelList } from '@/api/index.js'
import { ipcRenderer } from "electron";

export default {
  name: 'AiAuthWebview',
  props: {
    platform: {
      type: String,
      required: false
    },
    authId: {
      type: [String, Number],
      required: false
    }
  },
  data() {
    return {
      webviewUrl: '',
      modelName: '',
      webPreferences: 'nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=persist:session',
      modelData: null,
      models: [],
      currentPartition: '',
      isLoading: true,
      webviewElement: null,
      canGoBack: false,
      canGoForward: false,
      authData: null,
      hasInjectedData: false,
      modelUrlMap: {
        'deepseek': 'https://chat.deepseek.com/sign_in',
        'doubao': 'https://www.doubao.com/chat/',
        'yuanbao': 'https://yuanbao.tencent.com/chat/',
        'qianwen': 'https://www.qianwen.com/',
        'wenxin': 'https://yiyan.baidu.com/',
        'nami': 'https://www.n.cn/',
        'kimi': 'https://www.kimi.com/',
        'zhipu': 'https://chatglm.cn/'
      }
    }
  },
  async mounted() {
    const modelType = this.platform || this.$route.params.type
    if (modelType) {
      // 加载模型配置
      await this.loadModels()
      // 加载模型数据
      await this.loadModelData(modelType)
    } else {
      this.$message.error('缺少模型类型参数')
      this.closeWebview()
    }
  },
  methods: {
    async loadModels() {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo') || '{}')
        const params = { udid: userInfo.udid, uid: userInfo.uid }
        const response = await getModelList(params)
        if (response && response.code === 1 && response.data) {
          this.models = response.data
          console.log('加载模型配置:', this.models)
        }
      } catch (error) {
        console.error('加载模型配置失败:', error)
      }
    },

    async loadModelData(modelType) {
      try {
        console.log('查找模型类型:', modelType)
        
        this.modelData = this.models.find(model => model.platform_type === modelType)
        
        if (this.modelData) {
          console.log('找到模型数据:', this.modelData)
          this.modelName = this.modelData.name
          await this.setupWebview()
        } else {
          console.error('未找到模型数据，modelType:', modelType)
          console.log('所有模型类型:', this.models.map(m => m.platform_type))
          this.$message.error('模型信息不存在')
          this.closeWebview()
        }
      } catch (error) {
        console.error('加载模型数据失败:', error)
        this.$message.error('加载模型数据失败')
        this.closeWebview()
      }
    },

    async setupWebview() {
      // 设置代理
      await this.open_proyx()
      
      // 等待代理设置生效
      await new Promise(resolve => setTimeout(resolve, 500))
      
      const modelType = this.modelData.platform_type
      console.log('模型类型:', modelType)
      
      // 尝试从模型配置中获取URL
      let baseUrl = this.modelData.platform_ur
      
      // 如果模型配置中没有URL，使用默认映射
      if (!baseUrl) {
        baseUrl = this.modelUrlMap[modelType]

        console.log('使用默认URL映射:', baseUrl)
      }
      
      if (!baseUrl) {
        this.$message.error(`不支持的模型类型: ${modelType}`)
        this.closeWebview()
        return
      }


      if (modelType === 'qianwen') {
        baseUrl = 'https://www.qianwen.com/'
      }
      console.log('准备URL:', baseUrl)
      
      const uniquePartition = `ai_auth_session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
      this.currentPartition = uniquePartition
      this.webPreferences = `nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=persist:${uniquePartition}`
      
      // 设置 session 级别的 User-Agent
      try {
        const sessionInstance = session.fromPartition(`persist:${uniquePartition}`);
        sessionInstance.setUserAgent("Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.4389.90 Safari/537.36");
        console.log("已设置 session User-Agent");
        
        // 获取授权数据
        const authListStr = localStorage.getItem('authList')
        if (authListStr) {
          try {
            const authList = JSON.parse(authListStr)
            if (this.authId) {
              this.authData = authList.find(auth => auth.id == this.authId)
            } else if (this.platform) {
              this.authData = authList.find(auth => auth.platform === this.platform)
            }
            console.log('找到的授权数据:', this.authData)
          } catch (error) {
            console.error('解析授权列表失败:', error)
          }
        }
        
        // 注入cookies
        if (this.authData && this.authData.cookies) {
          try {
            const cookies = JSON.parse(decodeURIComponent(this.authData.cookies));
            console.log('准备注入的cookies:', cookies);
            
            // 清理和验证cookie数据
            const sanitizeCookie = (cookie) => {
              const sanitized = { ...cookie };
              if (!sanitized.name || !sanitized.value) {
                return null;
              }
              sanitized.name = String(sanitized.name).trim();
              sanitized.value = String(sanitized.value).trim();
              if (!sanitized.name || !sanitized.value) {
                return null;
              }
              sanitized.path = sanitized.path || '/';
              sanitized.secure = Boolean(sanitized.secure);
              sanitized.httpOnly = Boolean(sanitized.httpOnly);
              return sanitized;
            };
            
            let injectedCount = 0;
            let totalCount = 0;
            
            for (const cookie of cookies) {
              totalCount++;
              try {
                const sanitizedCookie = sanitizeCookie(cookie);
                if (!sanitizedCookie) {
                  console.warn(`跳过无效cookie: ${cookie.name || 'unknown'}`);
                  continue;
                }
                
                const cookieOptions = {
                  url: baseUrl,
                  name: sanitizedCookie.name,
                  value: sanitizedCookie.value,
                  path: sanitizedCookie.path,
                  secure: sanitizedCookie.secure,
                  httpOnly: sanitizedCookie.httpOnly,
                  sameSite: sanitizedCookie.sameSite || 'no_restriction'
                };
                
                if (sanitizedCookie.expirationDate) {
                  cookieOptions.expirationDate = sanitizedCookie.expirationDate;
                }
                
                await sessionInstance.cookies.set(cookieOptions);
                injectedCount++;
                console.log(`成功注入cookie: ${sanitizedCookie.name}`);
              } catch (cookieError) {
                console.error(`注入单个cookie失败 (${cookie.name || 'unknown'}):`, cookieError);
              }
            }
            console.log(`Cookies注入完成，成功注入 ${injectedCount} 个，总共 ${totalCount} 个`);
          } catch (error) {
            console.error('解析或注入cookies失败:', error);
          }
        }
      } catch (error) {
        console.error("设置 session 或注入数据失败:", error);
      }
      
      // 设置URL并显示webview
      this.webviewUrl = baseUrl
      this.isLoading = false
      
      await this.$nextTick()
      
      const webview = document.querySelector("webview")
      if (webview) {
        // 保存webview元素引用
        this.webviewElement = webview
        
        // 添加错误处理
        webview.addEventListener("did-fail-load", (event) => {
          console.error('Webview加载失败:', event)
        })
        
        webview.addEventListener("new-window", (e) => {
          console.log("处理新窗口事件")
          webview.src = e.url;
        });

        webview.addEventListener("did-finish-load", (event) => {
          // 注入localStorage和sessionStorage（仅kimi和deepseek需要）
          setTimeout(async () => {
            // 检查是否已经注入过数据，如果是则跳过
            if (this.hasInjectedData) {
              console.log('数据已经注入过，跳过');
              return;
            }
            
            // 只有kimi和deepseek需要注入localStorage和sessionStorage
            const modelType = this.modelData.platform_type;
            if (modelType !== 'kimi' && modelType !== 'deepseek') {
              console.log(`模型类型 ${modelType} 不需要注入localStorage和sessionStorage，跳过`);
              this.hasInjectedData = true;
              return;
            }
            
            try {
              console.log('开始注入localStorage和sessionStorage');
              
              if (this.authData) {
                console.log('解析后的authData:', this.authData);
                
                // 注入localStorage
                if (this.authData.localStorage) {
                  console.log('开始注入localStorage，原始数据:', this.authData.localStorage);
                  try {
                    const localStorageStr = decodeURIComponent(this.authData.localStorage);
                    console.log('解码后的localStorage字符串:', localStorageStr);
                    const localStorageData = JSON.parse(localStorageStr);
                    console.log('解析后的localStorage数据:', localStorageData);
                    
                    await webview.executeJavaScript(`
                      localStorage.clear();
                      console.log('已清空现有localStorage');
                      ${Object.entries(localStorageData).map(([key, value]) => {
                        const escapedKey = key.replace(/'/g, "\\'");
                        let escapedValue;
                        if (typeof value === 'string') {
                          escapedValue = `'${value.replace(/'/g, "\\'")}'`;
                        } else {
                          escapedValue = `'${JSON.stringify(value).replace(/'/g, "\\'")}'`;
                        }
                        return `console.log('注入localStorage项: ${escapedKey}', ${escapedValue}); localStorage.setItem('${escapedKey}', ${escapedValue});`;
                      }).join('\n')}
                    `);
                    console.log('localStorage注入成功', localStorageData);
                  } catch (error) {
                    console.error('localStorage数据解析或注入失败:', error);
                    console.error('错误堆栈:', error.stack);
                  }
                } else {
                  console.log('authData.localStorage为空，跳过注入');
                }
                
                // 注入sessionStorage
                if (this.authData.sessionStorage) {
                  console.log('开始注入sessionStorage，原始数据:', this.authData.sessionStorage);
                  try {
                    const sessionStorageStr = decodeURIComponent(this.authData.sessionStorage);
                    console.log('解码后的sessionStorage字符串:', sessionStorageStr);
                    const sessionStorageData = JSON.parse(sessionStorageStr);
                    console.log('解析后的sessionStorage数据:', sessionStorageData);
                    
                    await webview.executeJavaScript(`
                      sessionStorage.clear();
                      console.log('已清空现有sessionStorage');
                      ${Object.entries(sessionStorageData).map(([key, value]) => {
                        const escapedKey = key.replace(/'/g, "\\'");
                        let escapedValue;
                        if (typeof value === 'string') {
                          escapedValue = `'${value.replace(/'/g, "\\'")}'`;
                        } else {
                          escapedValue = `'${JSON.stringify(value).replace(/'/g, "\\'")}'`;
                        }
                        return `console.log('注入sessionStorage项: ${escapedKey}', ${escapedValue}); sessionStorage.setItem('${escapedKey}', ${escapedValue});`;
                      }).join('\n')}
                    `);
                    console.log('sessionStorage注入成功', sessionStorageData);
                  } catch (error) {
                    console.error('sessionStorage数据解析或注入失败:', error);
                    console.error('错误堆栈:', error.stack);
                  }
                } else {
                  console.log('authData.sessionStorage为空，跳过注入');
                }
              } else {
                console.log('authData为空，跳过注入');
              }
              
              this.hasInjectedData = true;
              console.log('数据注入完成，准备刷新页面');
              webview.reload();
            } catch (e) {
              console.error("注入localStorage或sessionStorage失败:", e);
              console.error("错误堆栈:", e.stack);
            }
          }, 1000);
          
          // 更新导航状态
          this.updateNavigationState();
        })
        
        // 监听导航状态变化
        webview.addEventListener("did-navigate", (event) => {
          this.updateNavigationState();
        })
        
        webview.addEventListener("did-navigate-in-page", (event) => {
          this.updateNavigationState();
        })
      }
    },

    closeWebview() {
      this.$emit('close')
    },

    // 刷新webview
    refresh() {
      if (this.webviewElement) {
        this.webviewElement.reload();
      }
    },

    // 后退
    goBack() {
      if (this.webviewElement) {
        this.webviewElement.goBack();
      }
    },

    // 前进
    goForward() {
      if (this.webviewElement) {
        this.webviewElement.goForward();
      }
    },

    // 更新导航状态
    updateNavigationState() {
      if (this.webviewElement) {
        this.canGoBack = this.webviewElement.canGoBack();
        this.canGoForward = this.webviewElement.canGoForward();
      }
    },

    // 设置代理
    async open_proyx() {
      console.log("open proxy0")
      const systemConfig = localStorage.getItem('systemConfig')
      const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
      if(agent_ip_url){
        console.log("open proxy success", agent_ip_url)
        ipcRenderer.send('proxyhandle', agent_ip_url)
      }
    }
  }
}
</script>

<style scoped lang="css">
.ai-auth-webview {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: var(--bg-primary);
  z-index: 9999;
  display: flex;
  flex-direction: column;
}

.webview-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 20px;
  background-color: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  z-index: 10000;
  min-height: 60px;
}

.webview-title {
  font-size: 18px;
  font-weight: bold;
  color: var(--text-primary);
}

.webview-close-btn {
  z-index: 10000;
}

.webview-nav-buttons {
  display: flex;
  gap: 8px; /* 按钮之间的间距 */
  margin-right: 15px; /* 与关闭按钮的间距 */
  align-items: center;
}

.nav-btn {
  padding: 6px 12px;
  font-size: 13px;
  border-radius: 4px;
}

.nav-btn i {
  margin-right: 4px;
}

.webview-container {
  flex: 1;
  width: 100%;
  height: calc(100% - 60px);
}

/* 新增加载状态样式 */
.loading-container {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  background-color: var(--bg-primary);
}

.loading-content {
  text-align: center;
  color: var(--text-secondary);
}

.loading-content i {
  font-size: 40px;
  margin-bottom: 10px;
  color: #3b82f6; /* 使用Element UI的主题色 */
  animation: rotate 2s linear infinite;
}

.loading-content p {
  font-size: 16px;
  margin: 0;
  color: var(--text-secondary);
}

@keyframes rotate {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}
</style>