<template>
  <div class="main-layout">
    <!-- 主内容区域 -->
    <div class="main-content">
      <!-- 公告栏 -->
      <div v-if="notice" class="notice-bar">
        <div class="notice-content">
          <i class="el-icon-warning-outline notice-icon"></i>
          <span class="notice-text">{{ notice }}</span>
        </div>
      </div>
      
      <!-- 顶部导航栏 -->
      <div class="header">
        <div class="header-left">
          <!-- <div class="brand">
            <div class="brand-icon">
              <i class="el-icon-s-tools"></i>
            </div>
            <div class="brand-name">授权助手</div>
          </div> -->
          
          <!-- 页面切换Tabs -->
          <div class="page-tabs">
            <div 
              class="tab-item" 
              :class="{ active: $route.path === '/home' }"
              @click="navigateTo('/home')">
              <i class="el-icon-s-home tab-icon"></i>
              <span>媒体管理</span>
            </div>
            <div 
              v-if="aiAuthorizationStatus"
              class="tab-item" 
              :class="{ active: $route.path === '/ai-auth' }"
              @click="navigateTo('/ai-auth')">
              <i class="el-icon-s-flag tab-icon"></i>
              <span>模型管理</span>
            </div>
          </div>
        </div>
        <div class="header-right">
          <!-- 帮助菜单 -->
          <div class="help-menu" @click.stop="toggleHelpMenu">
            <el-button type="text" class="help-button">
              <i class="el-icon-question"></i>
              <span>帮助</span>
            </el-button>
            <div v-if="showHelpMenu" class="help-dropdown">
              <div class="help-item" @click.stop="showAboutDialog">关于</div>
              <div class="help-item" @click.stop="checkForUpdates">检测更新</div>
              <div class="help-item" @click.stop="showConfigDialog">配置</div>
            </div>
          </div>
          <el-button type="primary" @click="openAdminInNewWindow" class="admin-button">
            <i class="el-icon-s-management"></i>
            <span>管理后台</span>
          </el-button>
          <div class="user-info-header">
            <el-avatar :size="32" :src="userInfo && userInfo.avatar ? userInfo.avatar : ''" class="user-avatar">
              {{ (userInfo && userInfo.username) ? userInfo.username.charAt(0).toUpperCase() : 'U' }}
            </el-avatar>
            <div class="user-details">
              <span class="username">{{ userInfo && userInfo.username ? userInfo.username : '用户' }}</span>
            </div>
          </div>
          <el-button type="text" @click="handleLogout" class="logout-button">
            <i class="el-icon-switch-button"></i>
            <span>退出登录</span>
          </el-button>
        </div>
      </div>

      <!-- 内容区域 -->
      <div class="content">
        <keep-alive>
          <router-view />
        </keep-alive>
      </div>
    </div>

    <!-- 关于弹窗 -->
    <el-dialog
      title=""
      :visible.sync="aboutDialogVisible"
      width="500px">
      <div class="about-content">
        <div class="about-announcements">
          <h5>系统公告</h5>
          <div v-if="announcements.length > 0" class="announcements-list">
            <div v-for="(announcement, index) in announcements" :key="`announcement_${index}`" class="announcement-item">
              <div class="announcement-header">
                <span class="announcement-title">{{ announcement.title }}</span>
                <span class="announcement-date">{{ announcement.time }}</span>
              </div>
              <div class="announcement-content">{{ announcement.content }}</div>
              <div v-if="announcement.type === '2'" class="announcement-badge">
                <el-tag type="danger" size="small">{{ announcement.type_info }}</el-tag>
              </div>
              <div v-else-if="announcement.type === '1'" class="announcement-badge">
                <el-tag type="warning" size="small">{{ announcement.type_info }}</el-tag>
              </div>
            </div>
          </div>
          <div v-else class="empty-announcements">
            暂无公告
          </div>
        </div>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="aboutDialogVisible = false">确定</el-button>
      </span>
    </el-dialog>

    <!-- 检测更新弹窗 -->
    <el-dialog
      title="检测更新"
      :visible.sync="updateDialogVisible"
      width="500px">
      <div class="update-content">
        <div class="version-info">
          <div class="version-item">
            <span class="label">当前版本:</span>
            <span class="value">{{ currentVersion }}</span>
          </div>
          <div class="version-item">
            <span class="label">最新版本:</span>
            <span class="value">{{ latestVersion }}</span>
          </div>
          <div v-if="hasUpdate" class="update-message">
            <el-alert
              title="发现新版本"
              type="success"
              :closable="false"
              show-icon>
              <div slot="default">
                <p>新版本 {{ latestVersion }} 已发布，是否立即下载更新？</p>
              </div>
            </el-alert>
          </div>
          <div v-else class="update-message">
            <el-alert
              title="已是最新版本"
              type="info"
              :closable="false"
              show-icon>
              <div slot="default">
                <p>当前版本已是最新，无需更新。</p>
              </div>
            </el-alert>
          </div>
        </div>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="updateDialogVisible = false">取消</el-button>
        <el-button v-if="hasUpdate" type="primary" @click="downloadUpdate">立即更新</el-button>
      </span>
    </el-dialog>

    <!-- 配置弹窗 -->
    <el-dialog
      title="系统配置"
      :visible.sync="configDialogVisible"
      width="500px">
      <div class="config-content">
        <el-form label-width="120px" class="config-form">
          <el-form-item label="谷歌浏览器路径">
            <el-input 
              v-model="systemConfig.googlePath" 
              placeholder="请输入谷歌浏览器可执行文件路径"
              size="medium">
            </el-input>
          </el-form-item>
          <!-- <el-form-item label="代理用户名">
            <el-input 
              v-model="systemConfig.agent_ip_username" 
              placeholder="请输入代理用户名"
              size="medium">
            </el-input>
          </el-form-item> -->
          <el-form-item label="代理URL">
            <div style="display: flex; gap: 10px; align-items: flex-start;">
              <el-input 
                v-model="systemConfig.agent_ip_url" 
                placeholder="格式为username:password@host:por"
                size="medium" style="flex: 1;">
              </el-input>
              <el-button type="info" size="medium" @click="testProxy">测试</el-button>
            </div>
            <div style="font-size: 12px; color: #909399; margin-top: 4px;color: red;">*配置代理后如果没生效，请重启软件生效</div>
          </el-form-item>
        </el-form>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="configDialogVisible = false">取消</el-button>
        <el-button type="primary" @click="saveSystemConfig">保存配置</el-button>
      </span>
    </el-dialog>
    
    <!-- 测试代理抽屉 -->
    <el-drawer
      title="代理测试"
      :visible.sync="testProxyDialogVisible"
      direction="rtl"
      size="80%"
      :close-on-click-modal="false">
      <div class="test-proxy-dialog">
        <!-- 加载状态显示 -->
        <div v-if="isTestProxyLoading" class="loading-container">
          <div class="loading-content">
            <i class="el-icon-loading"></i>
            <p>正在加载测试页面...</p>
          </div>
        </div>
        
        <!-- Webview容器 -->
        <webview 
          v-if="testProxyWebviewUrl && !isTestProxyLoading" 
          :src="testProxyWebviewUrl"
          class="webview-container"
          style="height: 85vh;"
          :partition="testProxyPartition"
          webpreferences="nodeIntegration=false, contextIsolation=true, webSecurity=true">
        </webview>
      </div>
    </el-drawer>
  </div>
</template>

<script>
import { getToken, removeToken } from '@/utils/auth.js'
import { ipcRenderer,shell } from "electron";
import request from '@/utils/request'
import packageInfo from '../../package.json'

export default {
  name: 'MainLayout',
  data() {
    return {
      userInfo: {
        username: '',
        avatar: ''
      },
      notice: '',
      // AI授权状态
      aiAuthorizationStatus: true, // 默认显示
      // 帮助菜单状态
      showHelpMenu: false,
      // 弹窗状态
      aboutDialogVisible: false,
      updateDialogVisible: false,
      configDialogVisible: false,
      // 版本信息
      currentVersion: '',
      latestVersion: '',
      hasUpdate: false,
      downloadUrl: '',
      // 公告信息
      announcements: [],
      // 系统配置
      systemConfig: {
        googlePath: '',
        agent_ip_username: '',
        agent_ip_url: ''
      },
      // 测试代理相关
      testProxyDialogVisible: false,
      testProxyUrl: 'https://www.ip38.com/',
      testProxyWebviewUrl: '',
      testProxyPartition: 'persist:testproxy',
      isTestProxyLoading: false
    }
  },
  computed: {
    pageTitle() {
      const routeMap = {
        '/home': '自媒体账号管理'
      }
      return routeMap[this.$route.path] || '账号管理'
    }
  },
  created() {
    this.loadUserInfo()
    this.fetchNotice()
    this.loadSystemConfig()
    this.getCurrentVersion()
    // 进入页面时自动检查版本
    this.autoCheckUpdate()
    // this.setupChromiumPath()
  },
  methods: {
    getPageSubtitle() {
      const subtitleMap = {
        '/home': '管理您的所有平台账号',
        '/push': '管理内容发布任务',
        '/settings': '配置系统参数和更新',
        '/ai-tools': '使用AI工具查询收录情况',
        '/ai-auth': '授权AI大模型访问权限',
        '/admin': '访问系统管理后台'
      }
      return subtitleMap[this.$route.path] || '欢迎使用AI Geo系统'
    },
    loadUserInfo() {
      try {
        const userInfoStr = localStorage.getItem('userInfo')
        if (userInfoStr) {
          const parsed = JSON.parse(userInfoStr)
          this.userInfo = {
            username: parsed.username || '',
            avatar: parsed.avatar || ''
          }
        }
      } catch (error) {
        console.warn('Failed to load user info:', error)
        this.userInfo = {
          username: '',
          avatar: ''
        }
      }
    },
    
    async setupChromiumPath() {
      try {
        // 通过 Electron 获取内置 Chromium 路径
    
          const chromiumPath = await ipcRenderer.invoke('get-chromium-path');
          console.log('获取到 Chromium 路径chromiumPath:', chromiumPath)
          if (chromiumPath) {
            console.log('获取到 Chromium 路径:', chromiumPath)
            // 设置到 Python 后端
            await this.setChromiumPathToBackend(chromiumPath)
          }
    
      } catch (error) {
        console.error('设置 Chromium 路径失败:', error)
      }
    },
    
    async setChromiumPathToBackend(chromiumPath) {
      try {
        const response = await fetch('/api/set-chromium-path', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ chromium_path: chromiumPath })
        })
        
        const result = await response.json()
        if (result.code === 1) {
          console.log('成功设置 Chromium 路径到后端:', result.msg)
        } else {
          console.error('设置 Chromium 路径失败:', result.msg)
        }
      } catch (error) {
        console.error('设置 Chromium 路径到后端失败:', error)
      }
    },
    navigateTo(path) {
      this.$router.push(path)
    },
    openAdminInNewWindow() {
      try {
        const userInfoStr = localStorage.getItem('userInfo')
        const user = userInfoStr ? JSON.parse(userInfoStr) : {}
        const udid = user.udid || ''
        const uid = user.uid || ''
        request.get('/api/zhushou/index', { params: { udid, uid } }).then(res => {
          const hostUrl = res && res.data && res.data.host_url
          if (hostUrl) {
            shell.openExternal(hostUrl)
          } else {
            this.$message.error('未获取到管理地址')
          }
        }).catch(err => {
          console.error('获取管理地址失败:', err)
          this.$message.error('获取管理地址失败')
        })
      } catch (e) {
        console.error('打开管理后台新窗口失败:', e)
        this.$message.error('打开失败')
      }
    },
    handleLogout() {
      this.$confirm('确定要退出登录吗？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        removeToken()
        localStorage.removeItem('userInfo')
        this.$router.push('/login')
        this.$message.success('已退出登录')
      })
    },
    
    async fetchNotice() {
      try {
        const userInfoStr = localStorage.getItem('userInfo')
        const user = userInfoStr ? JSON.parse(userInfoStr) : {}
        const udid = user.udid || ''
        const uid = user.uid || ''
        
        const response = await request.get('/api/zhushou/check_rule', { params: { udid, uid } })
        
        if (response.code === 1 && response.data) {
          // 更新公告
          if (response.data.notice) {
            this.notice = response.data.notice
          }
          // 更新AI授权状态
          if (response.data.ai_authorization_status !== undefined) {
            this.aiAuthorizationStatus = response.data.ai_authorization_status
          }
        }
      } catch (error) {
        console.error('获取公告失败:', error)
      }
    },
    
    // 帮助菜单相关方法
    toggleHelpMenu() {
      this.showHelpMenu = !this.showHelpMenu
    },
    
    // 显示关于弹窗
    async showAboutDialog() {
      this.showHelpMenu = false
      await this.fetchUpdateLog()
      this.aboutDialogVisible = true
    },
    
    // 检测更新
    async checkForUpdates() {
      this.showHelpMenu = false
      await this.fetchUpdateLog()
      this.updateDialogVisible = true
    },
    
    // 显示配置弹窗
    showConfigDialog() {
      this.showHelpMenu = false
      this.loadSystemConfig()
      this.configDialogVisible = true
    },
    
    // 获取当前版本
    getCurrentVersion() {
      this.currentVersion = "V" + packageInfo.version
    },
    
    // 获取设备信息
    getDeviceInfo() {
      const userInfo = JSON.parse(localStorage.getItem('userInfo') || '{}')
      return {
        udid: userInfo.udid,
        uid: userInfo.uid,
        version: packageInfo.version
      }
    },
    
    // 获取系统公告和版本信息
    async fetchUpdateLog() {
      try {
        const deviceInfo = this.getDeviceInfo()
        
        const response = await request({
          url: '/api/zhushou/get_update_log',
          method: 'get',
          params: deviceInfo
        })
        
        if (response.code === 1 && response.data) {
          // 更新公告列表
          this.announcements = response.data.logs || []
          
          // 更新版本信息
          if (response.data.new_version) {
            this.latestVersion = response.data.new_version
            // 移除版本号前缀V，然后进行版本比较
            const currentVersion = packageInfo.version.replace(/^V/, '')
            const latestVersion = response.data.new_version.replace(/^V/, '')
            // 使用版本号比较函数
            this.hasUpdate = this.compareVersions(latestVersion, currentVersion) > 0
          }
          
          // 保存版本下载地址
          if (response.data.version_url) {
            this.downloadUrl = response.data.version_url
          }
        }
        return response
      } catch (error) {
        console.error('获取更新日志失败:', error)
        this.$message.error('获取更新日志失败，请稍后重试')
        throw error
      }
    },
    
    // 下载更新
    downloadUpdate() {
      if (!this.downloadUrl) {
        this.$message.error('下载地址不可用')
        return
      }
      
      try {
        // 创建下载链接
        const link = document.createElement('a')
        link.href = this.downloadUrl
        link.download = `update-${this.latestVersion}.exe`
        link.target = '_blank'
        
        // 触发下载
        document.body.appendChild(link)
        link.click()
        document.body.removeChild(link)
        
        this.$message.success('开始下载更新文件')
        this.updateDialogVisible = false
      } catch (error) {
        console.error('下载文件失败:', error)
        this.$message.error('下载文件失败，请稍后重试')
      }
    },
    
    // 自动检查版本更新
    async autoCheckUpdate() {
      try {
        await this.fetchUpdateLog()
        // 如果有新版本，自动弹出更新弹窗
        if (this.hasUpdate) {
          this.updateDialogVisible = true
        }
      } catch (error) {
        console.error('自动检查版本失败:', error)
        // 静默失败，不影响用户体验
      }
    },
    
    // 比较版本号
    compareVersions(version1, version2) {
      const v1 = version1.split('.').map(Number)
      const v2 = version2.split('.').map(Number)
      
      for (let i = 0; i < Math.max(v1.length, v2.length); i++) {
        const num1 = v1[i] || 0
        const num2 = v2[i] || 0
        
        if (num1 > num2) return 1
        if (num1 < num2) return -1
      }
      
      return 0
    },
    
    // 加载系统配置
    loadSystemConfig() {
      try {
        const savedConfig = localStorage.getItem('systemConfig')
        if (savedConfig) {
          this.systemConfig = { ...this.systemConfig, ...JSON.parse(savedConfig) }
        }
      } catch (error) {
        console.error('加载配置失败:', error)
      }
    },
    
    // 保存系统配置
    saveSystemConfig() {
      try {
        localStorage.setItem('systemConfig', JSON.stringify(this.systemConfig))
        this.$message.success('配置已保存')
        // this.configDialogVisible = false
      } catch (error) {
        console.error('保存配置失败:', error)
        this.$message.error('保存配置失败，请稍后重试')
      }
    },
    open_proyx(){
      console.log("open proxy0",this.agent_ip_url)
      const systemConfig = localStorage.getItem('systemConfig')
      this.agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
      if(this.agent_ip_url){
        console.log("open proxy success",this.agent_ip_url)
        ipcRenderer.send('proxyhandle',this.agent_ip_url)
      }
    },
    
    // 测试代理
    async testProxy() {
      await this.open_proyx()
      
      // 生成唯一的partition名称
      const uniquePartition = `testproxy_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
      this.testProxyPartition = `persist:${uniquePartition}`
      
      this.testProxyDialogVisible = true
      this.isTestProxyLoading = true
      setTimeout(async () => {
        this.testProxyWebviewUrl = this.testProxyUrl
        this.isTestProxyLoading = false
        
        await this.$nextTick()
        
        const webview = document.querySelector(".test-proxy-dialog webview")
        if (webview) {
          webview.addEventListener("new-window", (e) => {
            console.log("处理点击事件")
            webview.src = e.url
          })
          
          webview.addEventListener("did-finish-load", () => {
            console.log("Webview加载完成")
          })
        }
      }, 500)
    },
    
    // 关闭测试代理弹窗
    closeTestProxyDialog() {
      this.testProxyDialogVisible = false
      this.testProxyWebviewUrl = ''
    }
  }
}
</script>

<style scoped lang="scss">
.main-layout {
  display: flex;
  height: 100%;
  background-color: var(--bg-primary);
  overflow: hidden;
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  
  .notice-bar {
    background: linear-gradient(135deg, #FFF3CD 0%, #FFF7E6 100%);
    border-bottom: 1px solid #FFE082;
    padding: 8px 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    
    .notice-content {
      display: flex;
      align-items: center;
      gap: 12px;
      max-width: 1200px;
      width: 100%;
      
      .notice-icon {
        color: #FFC107;
        font-size: 18px;
      }
      
      .notice-text {
        color: #856404;
        font-size: 14px;
        line-height: 1.4;
        flex: 1;
      }
    }
  }
  
  .header {
    height: 80px;
    border-bottom: 1px solid var(--border-color);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 40px;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
    position: relative;
    
    .header-left {
      display: flex;
      align-items: center;
      gap: 40px;
      
      .brand {
        display: flex;
        align-items: center;
        gap: 12px;
        
        .brand-icon {
          width: 40px;
          height: 40px;
          border-radius: var(--radius-md);
          background: var(--gradient-primary);
          display: flex;
          align-items: center;
          justify-content: center;
          box-shadow: 0 2px 8px rgba(59, 130, 246, 0.3);
          
          i {
            font-size: 20px;
            color: white;
          }
        }
        
        .brand-name {
          color: var(--text-primary);
          font-size: 18px;
          font-weight: 700;
          font-family: 'Orbitron', sans-serif;
          letter-spacing: 1px;
        }
      }
      
      .page-tabs {
        display: flex;
        gap: 2px;
        background: var(--bg-tertiary);
        border-radius: var(--radius-lg);
        padding: 4px;
        position: relative;
        z-index: 1;
        
        .tab-item {
          display: flex;
          align-items: center;
          gap: 8px;
          padding: 8px 20px;
          border-radius: var(--radius-md);
          cursor: pointer;
          transition: all 0.3s ease;
          color: var(--text-secondary);
          font-weight: 500;
          position: relative;
          z-index: 2;
          
          &:hover {
            background: rgba(59, 130, 246, 0.1);
            color: var(--text-primary);
          }
          
          &.active {
            background: var(--gradient-primary);
            color: white;
            box-shadow: 0 2px 8px rgba(59, 130, 246, 0.3);
          }
          
          .tab-icon {
            font-size: 16px;
          }
        }
      }
    }
    
    .header-right {
        display: flex;
        align-items: center;
        gap: 24px;
        position: relative;
        z-index: 1;
        
        .help-menu {
          position: relative;
          
          .help-button {
            display: flex;
            align-items: center;
            gap: 6px;
