<template>
  <div class="ai-auth">
    <div class="page-container">
      <!-- 左侧平台列表 -->
      <div class="left-sidebar">
        <div class="sidebar-header">
          <h3 class="sidebar-title">账号授权</h3>
        </div>
        <div class="platform-list">
          <div 
            v-for="model in models" 
            :key="model.value"
            :class="['platform-item', { 'platform-item-active': selectedPlatform === model.value }]"
            @click="filterByPlatform(model.value)">
            <div class="platform-item-inner">
              <div class="platform-item-icon">
                <el-avatar :size="32" :src="model.icon">{{ model.label.charAt(0) }}</el-avatar>
              </div>
              <div class="platform-item-info">
                <span class="platform-item-name">{{ model.label }}</span>
                <span class="platform-item-count">{{ model.count }}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 右侧内容区域 -->
      <div class="right-content">
        <!-- 顶部搜索和操作区域 -->
        <div class="top-bar">
          <div class="search-container">
            <el-input
              v-model="searchForm.name"
              placeholder="请输入授权名称"
              prefix-icon="el-icon-search"
              class="search-input"
            />
            <el-select v-model="searchForm.status" placeholder="授权状态" class="status-select" clearable @clear="handleSearch">
              <el-option label="全部" value=""></el-option>
              <el-option label="已授权" value="true"></el-option>
              <el-option label="未授权" value="false"></el-option>
            </el-select>
          </div>
          <div class="action-buttons">
            <el-button type="primary" class="action-button" @click="refreshAuthList">
              <i class="el-icon-refresh"></i>
              刷新列表
            </el-button>
            <el-button type="success" class="action-button" @click="openAddAuthDialog">
            <i class="el-icon-plus"></i>
            新增授权
          </el-button>
          <el-button v-if="aiSelectStatus" type="warning" class="action-button" @click="openAiToolsDrawer">
            <i class="el-icon-edit"></i>
            查询
          </el-button>
          </div>
        </div>

        <!-- 授权列表 -->
        <div class="account-table-container" v-if="!webviewUrl">
          <el-table
            :data="filteredAuthList"
            v-loading="loading"
            style="width: 100%"
            class="account-table"
            ref="multipleTable">
            <el-table-column label="头像" min-width="80" align="center">
              <template slot-scope="scope">
                <el-avatar :size="32" :src="scope.row.avatar" class="nickname-avatar">
                  {{ (scope.row.nickname || scope.row.name || 'U').charAt(0) }}
                </el-avatar>
              </template>
            </el-table-column>
            <el-table-column prop="nickname" label="授权名称" min-width="150" align="center">
              <template slot-scope="scope">
                <span class="nickname-text">{{ scope.row.nickname || scope.row.name || '未命名授权' }}</span>
              </template>
            </el-table-column>
            <el-table-column label="平台" min-width="120" align="center">
              <template slot-scope="scope">
                <div class="platform-cell">
                  <el-avatar :size="24" :src="getPlatformIcon(scope.row.platform)" class="platform-avatar"></el-avatar>
                  <span class="platform-text">{{ getPlatformName(scope.row.platform) }}</span>
                </div>
              </template>
            </el-table-column>
            <el-table-column label="授权状态" min-width="100" align="center">
              <template slot-scope="scope">
                <span :class="{'status-tag-success': scope.row.status, 'status-tag-danger': !scope.row.status}">
                   {{ scope.row.status ? '已授权' : '未授权' }}
                </span>
              </template>
            </el-table-column>
            <el-table-column prop="auth_time" label="授权时间" min-width="180" align="center">
              <template slot-scope="scope">
                <span class="time-text">{{ formatTime(scope.row.auth_time) }}</span>
              </template>
            </el-table-column>
            <el-table-column label="操作" min-width="150" align="center">
              <template slot-scope="scope">
                <div class="table-action-buttons">
                  <el-button size="small" type="primary" @click="handleEnterAuth(scope.row)" class="table-action-button primary">
                    <i class="el-icon-view"></i>
                    登入
                  </el-button>
                  <el-button size="small" type="danger" @click="deleteAuth(scope.row, scope.$index)" class="table-action-button danger">
                    <i class="el-icon-delete"></i>
                    删除
                  </el-button>
                </div>
              </template>
            </el-table-column>
          </el-table>

          <!-- 分页 -->
          <div class="pagination-wrapper">
            <el-pagination
              @size-change="handleSizeChange"
              @current-change="handleCurrentChange"
              :current-page="pagination.current"
              :page-sizes="[10, 20, 50, 100]"
              :page-size="pagination.size"
              layout="total, sizes, prev, pager, next, jumper"
              :total="pagination.total"
              class="account-pagination">
            </el-pagination>
          </div>
        </div>
      </div>
    </div>

    <!-- Webview授权区域 -->
    <div v-if="webviewUrl" class="webview-overlay">
      <!-- 关闭按钮放在webview外面顶部 -->
      <div class="webview-header">
        <div class="webview-title">
          <i class="el-icon-lock"></i>
          <span>{{ getPlatformName(selectedPlatform) }} - 授权</span>
        </div>
        <div class="webview-actions">
          <el-button 
            class="webview-close-btn" 
            type="danger" 
            size="small"
            @click="closeAuthWebview">
            <i class="el-icon-close"></i>
            完成授权
          </el-button>
        </div>
      </div>
      
      <webview 
        v-if="webviewUrl" 
        :src="webviewUrl"
        class="webview-container"
        :preload="preload"
        :partition="sessionPartition"
        allowpopups
      >
      </webview>
    </div>

    <!-- 新增授权弹窗 -->
    <el-dialog
      title="选择AI平台"
      :visible.sync="addAuthDialogVisible"
      width="800px"
      center>
      <div class="platform-selection-grid">
        <div 
          v-for="model in models" 
          :key="model.value"
          class="platform-selection-item"
          :class="{ disabled: !model.status }"
          @click="selectPlatformForAuth(model)">
          <div class="platform-selection-icon">
            <el-avatar :size="48" :src="model.icon">{{ model.label.charAt(0) }}</el-avatar>
          </div>
          <div class="platform-selection-info">
            <h4 class="platform-selection-name">{{ model.label }}</h4>
            <p class="platform-selection-desc">{{ model.status ? '点击进行授权' : '暂未开放' }}</p>
          </div>
        </div>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="addAuthDialogVisible = false">取消</el-button>
      </span>
    </el-dialog>

    <!-- AI授权Webview弹窗 -->
    <div v-if="aiAuthWebviewVisible" class="account-webview-overlay">
      <AiAuthWebview 
        :platform="selectedAuthPlatform"
        :auth-id="selectedAuthId"
        @close="closeAiAuthWebview"
      />
    </div>

    <!-- AI工具 Drawer -->
    <el-drawer
      title="查询管理"
      :visible.sync="aiToolsDrawerVisible"
      direction="rtl"
      size="80%">
      <AiTools />
    </el-drawer>
  </div>
</template>

<script>
const { session } = require('@electron/remote')
import { getModelList, saveModelCookie, getModelUserList, deleteModelUser, checkRule } from '@/api/index.js'
import { getScript,getAiScript } from '@/utils/index'
import { deepseekLogin, kimiLogin, send_exe } from '@/api/push'
import AiAuthWebview from './AiAuthWebview.vue'
import AiTools from './AiTools.vue'
import { ipcRenderer } from "electron";
export default {
  components: {
    AiAuthWebview,
    AiTools
  },
  name: 'AiAuth',
  data() {
    return {
      models: [],
      selectedPlatform: '',
      authList: [],
      udid: '',
      uid: '',
      loading: false,
      agent_ip_url: '',
      agent_ip_username: '',
      searchForm: {
        name: '',
        status: '',
        platform: ''
      },
      pagination: {
        current: 1,
        size: 10,
        total: 0
      },
      webviewUrl: '',
      preload: '',
      webPreferences: 'nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=persist:session',
      // 授权登录过程中的状态
      postData: null,
      loginSuccess: false,
      sessionPartition: '',
      modelUrlMap: {
        'deepseek': 'https://chat.deepseek.com/sign_in',
        'doubao': 'https://www.doubao.com/chat/',
        'yuanbao': 'https://yuanbao.tencent.com/chat/',
        'qianwen': 'https://www.tongyi.com/',
        'wenxin': 'https://yiyan.baidu.com/',
        'nami': 'https://www.n.cn/',
        'kimi': 'https://www.kimi.com/',
        'zhipu': 'https://chatglm.cn/'
      },
      // 模型ID映射
      modelIdMap: {
        'deepseek': 1,
        'doubao': 2,
        'yuanbao': 3,
        'qianwen': 4,
        'wenxin': 5,
        'nami': 6,
        'kimi': 7,
        'zhipu': 8
      },
      addAuthDialogVisible: false,
      aiAuthWebviewVisible: false,
      selectedAuthPlatform: null,
      selectedAuthId: null,
      aiToolsDrawerVisible: false,
      aiSelectStatus: 0 // 模型发布按钮显示状态
    }
  },
  computed: {
    filteredAuthList() {
      let filtered = this.authList;
      
      // 按平台筛选
      if (this.searchForm.platform) {
        filtered = filtered.filter(auth => auth.platform === this.searchForm.platform);
      }
      
      // 按名称筛选
      if (this.searchForm.name) {
        const keyword = this.searchForm.name.toLowerCase();
        filtered = filtered.filter(auth => 
          (auth.nickname && auth.nickname.toLowerCase().includes(keyword)) ||
          (auth.name && auth.name.toLowerCase().includes(keyword))
        );
      }
      
      // 按状态筛选
      if (this.searchForm.status) {
        filtered = filtered.filter(auth => 
          auth.status.toString() === this.searchForm.status
        );
      }
      
      return filtered;
    }
  },

  activated(){
		this.$refs['multipleTable'].doLayout()
	},
  async mounted() {
    const userInfoStr = localStorage.getItem('userInfo')
    const userInfo = JSON.parse(userInfoStr)
    this.udid = userInfo.udid
    this.uid = userInfo.uid
    
    await this.loadModels()
    this.loadAuthList()
    this.get_send_exe()
    this.checkAiSelectStatus() // 检查AI选择状态
  },
  methods: {
    async get_send_exe() {
      try {
        // 调用接口获取代理信息
        const res = await send_exe({
          udid: this.udid,
          uid: this.uid
        });
        
        if (res && res.code === 1 && res.data) {
          const d = res.data
          this.agent_ip_username = d.agent_ip_username
          this.agent_ip_url = d.agent_ip_url
          console.log('获取代理信息成功:', this.agent_ip_url)
        }
      } catch (error) {
        console.error('获取代理信息失败:', error)
      }
    },
    
    async loadModels() {
      try {
        const response = await getModelList({ udid: this.udid, uid: this.uid })
        if (response && response.code === 1 && response.data) {
          this.models = response.data.map(item => ({
            label: item.name,
            value: item.platform_type,
            icon: item.avatar,
            status: item.status
          }))
          console.log('模型列表加载成功:', this.models)
        }
      } catch (error) {
        console.error('加载模型列表失败:', error)
        this.$message.error('加载模型列表失败')
      }
    },
    open_proyx(){
      console.log("open proxy0",this.agent_ip_url)
      // 获取系统配置中的谷歌浏览器路径
      const systemConfig = localStorage.getItem('systemConfig')
      this.agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
      if(this.agent_ip_url){
        console.log("open proxy success",this.agent_ip_url)
        ipcRenderer.send('proxyhandle',this.agent_ip_url)
      }
    },

    async selectPlatform(platformType, status) {
      if (!status) {
        this.$message.warning('该平台暂不可用')
        return
      }
      this.selectedPlatform = platformType
      await this.open_proyx()
      // 如果平台是 deepseek 或 nami，则调用 API 授权接口
      if (platformType === 'deepseek2' || platformType === 'kimi2') {
        try {
          // 获取系统配置中的谷歌浏览器路径
          const systemConfig = localStorage.getItem('systemConfig')
          const googlePath = systemConfig ? JSON.parse(systemConfig).googlePath || '' : ''
          const agent_ip_url = systemConfig ? JSON.parse(systemConfig).agent_ip_url || '' : ''
          const agent_ip_username = systemConfig ? JSON.parse(systemConfig).agent_ip_username || '' : ''
          const data = {
            udid: this.udid,
            uid: this.uid,  
            platform: platformType,
            googlePath: googlePath,
            agent_ip_url: agent_ip_url,
            agent_ip_username: agent_ip_username
          }
          
          let loginPromise;
          if (platformType === 'deepseek') {
            loginPromise = deepseekLogin(data);
          } else {
            loginPromise = kimiLogin(data);
          }
          
          loginPromise.then(response => {
            console.log(`${platformType} response`, response)
            if (response && response.code === 1) {
              this.$message.success(`${platformType === 'deepseek' ? 'Deepseek' : 'Nami'}授权成功`)
              // 授权成功后刷新授权列表
              this.loadAuthList()
            } else {
              this.$message.error(response?.msg || `${platformType === 'deepseek' ? 'Deepseek' : 'Nami'}授权失败`)
            }
          }).catch(error => {
            console.error(`${platformType}授权失败:`, error)
            this.$message.error(`${platformType === 'deepseek' ? 'Deepseek' : 'Nami'}授权失败: ${error.message}`)
          }).finally(() => {
            this.loading = false
          })
        } catch (error) {
          console.error(`${platformType}授权失败:`, error)
          this.$message.error(`${platformType === 'deepseek' ? 'Deepseek' : 'Nami'}授权失败: ${error.message}`)
          this.loading = false
        }
      } else {
        // 其他平台使用原有的 webview 授权方式
        this.startAuth(platformType)
      }
    },

    getPlatformName(platformType) {
      const model = this.models.find(m => m.value === platformType)
      return model ? model.label : platformType
    },

    getPlatformIcon(platformType) {
      const model = this.models.find(m => m.value === platformType)
      return model ? model.icon : ''
    },

    getPlatformTypeFromModel(modelId) {
      // 根据模型ID反向查找平台类型
      const platformType = Object.keys(this.modelIdMap).find(key => this.modelIdMap[key] === modelId)
      return platformType || 'unknown'
    },

    async startAuth(platformType) {
      if (!platformType) {
        this.$message.warning('请先选择平台')
        return
      }
      
      // 获取平台URL
      const model = this.models.find(m => m.value === platformType)
      let baseUrl = model ? model.platform_ur : null
      
      if (!baseUrl) {
        baseUrl = this.modelUrlMap[platformType]
      }
      
      if (!baseUrl) {
        this.$message.error(`不支持的平台类型: ${platformType}`)
        return
      }
      
      // 初始化授权提交数据
      this.postData = {
        udid: this.udid,
        uid: this.uid,
        cookie: '',
        state: '',
        avatar: '',
        nickname: '',
        unique_id: '',
        model: this.modelIdMap[platformType] || 1
      }
      this.loginSuccess = false
      
      // 获取preload脚本
      this.preload = await getAiScript(platformType)
      console.log("获取到preload脚本:", this.preload)
      
      // 生成唯一的partition名称，确保每次都是新的会话
      const uniquePartition = `ai_auth_session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      this.sessionPartition = `persist:${uniquePartition}`
      this.webPreferences = `nodeIntegration=false, contextIsolation=true, webSecurity=true, partition=${this.sessionPartition}`;
      
      // 显示授权webview
      this.webviewUrl = baseUrl
      console.log("显示授权webview:", this.webviewUrl)
      
      await this.$nextTick();
      const webview = document.querySelector("webview");

      webview.addEventListener("did-finish-load", (e) => {
        webview.addEventListener("ipc-message", (event) => {
          console.log(
            "收到AI授权登录成功的通讯了",
            event.channel,
            event.args[0]
          );
          if (event.channel == 'checkLogin' || event.channel == 'value') {
            if (this.postData && this.postData.nickname) return; // 已经接收到了数据，不再处理
            const data = event.args[0] || {};
            this.postData = {
              ...(this.postData || {}),
              nickname: data.name || '',
              avatar: data.avatar || '',
              cookie: data.cookie || (this.postData ? this.postData.cookie : ''),
              unique_id: data.account || '',
            }
            console.log("收到AI授权成功通知", this.postData)
            this.loginSuccess = 1
          }
        });
        webview.send('checkLogin', { data: "主进程收到的消息，建立ipc-message链接" });
        // webview.openDevTools();
      });
    },

    async refreshWebview() {
      const webview = document.querySelector("webview");
      if (webview) {
        webview.reload();
        this.$message.info('正在刷新页面...');
      }
    },
    
    async closeAuthWebview() {
      const webview = document.querySelector("webview");
      const hasLoginData = this.postData && this.loginSuccess == 1
      console.log("hasLoginData", hasLoginData)
      console.log("this.sessionPartition", this.sessionPartition)
      
      if (hasLoginData && this.sessionPartition && webview) {
        try {
          // 读取当前 webview 分区中的所有 cookies
          const cookie = await session.fromPartition(this.sessionPartition).cookies.get({});
          
          console.log("获取到cookie", cookie);
          
          const encodedCookies = encodeURIComponent(JSON.stringify(cookie));
          console.log("cookie=====", encodedCookies);

          // 获取 localStorage 数据
          const localStorageData = await webview.executeJavaScript(`
            JSON.stringify({ ...localStorage })
          `);
          const encodedLocalStorage = encodeURIComponent(localStorageData);
          console.log("localStorage=====", encodedLocalStorage);

          // 获取 sessionStorage 数据
          const sessionStorageData = await webview.executeJavaScript(`
            JSON.stringify({ ...sessionStorage })
          `);
          const encodedSessionStorage = encodeURIComponent(sessionStorageData);
          console.log("sessionStorage=====", encodedSessionStorage);

          this.postData.cookie = encodedCookies;
          this.postData.localStorage = encodedLocalStorage;
          this.postData.sessionStorage = encodedSessionStorage;

          //暂时传空，因为文件过大
          // this.postData.localStorage = "";
          // this.postData.sessionStorage = "";
          
          await this.saveModelAuth(this.postData);
        } catch (e) {
          console.error("数据操作失败:", e);
          this.$message.error(`授权失败: ${e.message}`);
        }
      } else if (this.postData && this.sessionPartition && webview) {
        // 授权失败，但有postData和sessionPartition，弹出二次弹窗让用户手动输入nickname
        console.log('触发二次弹窗逻辑');
        
        // 保存当前postData和sessionPartition的副本，防止后续被清空
        const postDataCopy = { ...this.postData };
        const sessionPartitionCopy = this.sessionPartition;
        
        try {
          // 读取当前 webview 分区中的所有 cookies
          const cookie = await session.fromPartition(sessionPartitionCopy).cookies.get({});
          const encodedCookies = encodeURIComponent(JSON.stringify(cookie));
          console.log("二次弹窗获取到cookie", cookie);
          
          // 获取 localStorage 数据
          const localStorageData = await webview.executeJavaScript(`
            JSON.stringify({ ...localStorage })
          `);
          const encodedLocalStorage = encodeURIComponent(localStorageData);
          // 暂时传空，因为文件过大
          // const encodedLocalStorage = ""
          console.log("二次弹窗获取到localStorage", localStorageData);
          
          // 获取 sessionStorage 数据
          const sessionStorageData = await webview.executeJavaScript(`
            JSON.stringify({ ...sessionStorage })
          `);

          //暂时传空，因为文件过大
          const encodedSessionStorage = encodeURIComponent(sessionStorageData);
          // const encodedSessionStorage = ""
          console.log("二次弹窗获取到sessionStorage", sessionStorageData);

  
          this.$prompt(
            '授权自动检测失败，如已登录成功，请手动输入账号昵称进行授权:',
            '授权确认',
            {
              confirmButtonText: '确认',
              cancelButtonText: '取消',
              inputPattern: /^[\S]+$/,
              inputErrorMessage: '昵称不能为空'
            }
          ).then(async ({ value }) => {
            // 创建最终的提交数据
            const finalData = {
              ...postDataCopy,
              nickname: value,
              cookie: encodedCookies,
              localStorage: encodedLocalStorage,
              sessionStorage: encodedSessionStorage
            };
            
            console.log('二次弹窗最终提交数据:', finalData);
            
            // 保存授权数据
            try {
              await this.saveModelAuth(finalData);
            } catch (saveError) {
              console.error("保存AI模型授权失败:", saveError);
              this.$message.error(`保存失败: ${saveError.message}`);
            }
          }).catch(() => {
            console.log('用户取消了手动授权');
            this.$message.info('已取消授权');
          });
        } catch (e) {
          console.error("二次弹窗处理失败:", e);
          this.$message.error(`手动授权处理失败: ${e.message}`);
        }
      } else {
        this.$message.error('授权失败，未登录成功')
      }
      
      // 清理 webview 和 session
      if (webview) {
        try {
          if (this.sessionPartition) {
            const sessionInstance = session.fromPartition(this.sessionPartition);
            
            // 清除缓存
            sessionInstance.clearCache().then(() => {
              console.log('缓存已清除');
            }).catch(err => {
              console.error('清除缓存失败:', err);
            });
            
            // 清除存储数据
            sessionInstance.clearStorageData({
              storages: ['appcache', 'cookies', 'filesystem', 'indexdb', 'localstorage', 
                        'shadercache', 'websql', 'serviceworkers', 'cachestorage'],
            }).then(() => {
              console.log('存储数据已清除');
            }).catch(err => {
              console.error('清除存储数据失败:', err);
            });
          }
        } catch (error) {
          console.error('清理 Webview 失败:', error);
        }
      }

      // 清理 Session 分区
      // if (this.sessionPartition) {
      //   try {
      //     const sessionInstance = session.fromPartition(this.sessionPartition.replace('persist:', ''));
          
      //     // 使用新的API清理session
      //     await sessionInstance.clearCache();
      //     await sessionInstance.clearStorageData({
      //       storages: ['appcache', 'cookies', 'filesystem', 'indexdb', 'localstorage', 
      //                 'shadercache', 'websql', 'serviceworkers', 'cachestorage'],
      //     });
      //   } catch (error) {
      //     console.error('清理 Session 失败:', error);
      //   }
      // }
      
      this.webviewUrl = ''
      this.selectedPlatform = ''
      this.postData = null
      this.loginSuccess = false
      this.sessionPartition = ''
    },

    // 保存AI模型授权
    async saveModelAuth(data) {
      try {
        const response = await saveModelCookie(data)
        if (response && response.code === 1) {
          this.$message.success('AI模型授权成功')
          // 授权成功后刷新授权列表
          this.loadAuthList()
        } else {
          this.$message.error(response?.msg || 'AI模型授权失败')
        }
      } catch (error) {
        console.error('AI模型授权失败:', error)
        this.$message.error(`AI模型授权失败: ${error.message}`)
      }
    },

    enterAccount(auth) {
      // 将授权数据存储到localStorage，供webview组件使用
      const authList = this.authList
      localStorage.setItem('authList', JSON.stringify(authList))
      this.selectedAuthPlatform = auth.platform
      this.aiAuthWebviewVisible = true
    },

    handleEnterAuth(auth) {
      // 将授权数据存储到localStorage，供webview组件使用
      const authList = this.authList
      localStorage.setItem('authList', JSON.stringify(authList))
      this.selectedAuthPlatform = auth.platform
      this.selectedAuthId = auth.id
      this.aiAuthWebviewVisible = true
    },

    refreshAuthList() {
      this.loadAuthList()
      this.$message.success('授权列表已刷新')
    },

    async loadAuthList() {
      this.loading = true
      try {
        // 获取所有授权列表，不传model参数
        const params = {
          udid: this.udid,
          uid: this.uid,
          page: 1,
          size: 100 // 获取所有数据
        }
        
        const response = await getModelUserList(params)
        if (response && response.code === 1 && response.data && response.data.user_list) {
          // 为每个授权项添加平台信息
          this.authList = response.data.user_list.map(item => ({
            ...item,
            platform: this.getPlatformTypeFromModel(item.model),
            status: item.status === true || item.status === 'true'
          }))
          this.pagination.total = this.authList.length
        } else {
          this.authList = []
          this.pagination.total = 0
        }
        
        console.log('授权列表加载成功:', this.authList)
      } catch (error) {
        console.error('加载授权列表失败:', error)
        this.$message.error('加载授权列表失败')
        this.authList = []
        this.pagination.total = 0
      } finally {
        this.loading = false
      }
    },

    editAuth(auth) {
      this.$message.info(`编辑授权: ${auth.name}`)
      // 实际实现中打开编辑弹窗
    },

    testAuth(auth) {
      this.$message.info(`测试授权: ${auth.name}`)
      // 实际实现中测试授权有效性
    },

    async deleteAuth(auth, index) {
      this.$confirm(`确定要删除授权 "${auth.name}" 吗？`, '确认删除', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(async () => {
        this.loading = true
        try {
          const params = {
            udid: this.udid,
            uid: this.uid,
            model_user_id: auth.id
          }
          
          const response = await deleteModelUser(params)
          if (response && response.code === 1) {
            // 从列表中移除该项
            this.authList.splice(index, 1)
            this.$message.success('授权已删除')
          } else {
            this.$message.error(response?.msg || '删除授权失败')
          }
        } catch (error) {
          console.error('删除授权失败:', error)
          this.$message.error(`删除授权失败: ${error.message}`)
        } finally {
          this.loading = false
        }
      }).catch(() => {
        this.$message.info('已取消删除')
      })
    },

    formatTime(date) {
      if (!date) return '-'
      return new Date(date).toLocaleString('zh-CN')
    },

    // 搜索
    handleSearch() {
      this.pagination.current = 1
      this.loadAuthList()
    },

    // 重置搜索
    handleReset() {
      this.searchForm = {
        name: '',
        status: '',
        platform: ''
      }
      this.selectedPlatform = ''
      this.pagination.current = 1
      this.loadAuthList()
    },

    // 分页处理
    handleSizeChange(val) {
      this.pagination.size = val
      this.loadAuthList()
    },

    handleCurrentChange(val) {
      this.pagination.current = val
      this.loadAuthList()
    },

    // 打开新增授权弹窗
    openAddAuthDialog() {
      this.addAuthDialogVisible = true;
    },

    // 选择平台进行授权
    selectPlatformForAuth(model) {
      if (!model.status) {
        this.$message.warning('该平台暂不可用');
        return;
      }
      this.addAuthDialogVisible = false;
      this.selectPlatform(model.value, model.status);
    },

    // 按平台筛选授权
    filterByPlatform(platformType) {
      if (this.selectedPlatform === platformType) {
        // 取消选中，查询全部
        this.selectedPlatform = '';
        this.searchForm.platform = '';
      } else {
        // 选中平台
        this.selectedPlatform = platformType;
        this.searchForm.platform = platformType;
      }
      this.pagination.current = 1;
      this.loadAuthList();
    },

    // 关闭AI授权Webview
    closeAiAuthWebview() {
      this.aiAuthWebviewVisible = false;
      this.selectedAuthPlatform = null;
      this.selectedAuthId = null;
    },

    // 打开AI工具 Drawer
    openAiToolsDrawer() {
      this.aiToolsDrawerVisible = true;
    },
    
    async checkAiSelectStatus() {
      try {
        const response = await checkRule({ udid: this.udid, uid: this.uid })
        if (response && response.code === 1 && response.data) {
          this.aiSelectStatus = response.data.ai_select_status
        }
      } catch (error) {
        console.error('获取AI选择状态失败:', error)
      }
    }

  }
}
</script>

